import React, { useState } from 'react';
import { parsePatientData } from '../services/geminiService';
import { Patient } from '../types';
import { Sparkles, FileSpreadsheet, Download, Copy, Trash2, Plus, Loader2 } from 'lucide-react';

interface PatientManagerProps {
  patients: Patient[];
  onAddPatient: (patient: Patient) => void;
  onDeletePatient: (id: string) => void;
}

export const PatientManager: React.FC<PatientManagerProps> = ({ patients, onAddPatient, onDeletePatient }) => {
  const [inputText, setInputText] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleProcess = async () => {
    if (!inputText.trim()) return;

    setIsProcessing(true);
    setError(null);
    try {
      const parsedData = await parsePatientData(inputText);
      if (parsedData) {
        const newPatient: Patient = {
          id: crypto.randomUUID(),
          fecha: new Date().toLocaleDateString('es-ES'),
          ...parsedData
        };
        onAddPatient(newPatient);
        setInputText(''); // Clear input on success
      } else {
        setError('No se pudo interpretar la información. Intenta ser más claro.');
      }
    } catch (err: any) {
      setError(err.message || 'Error al conectar con la IA.');
    } finally {
      setIsProcessing(false);
    }
  };

  const exportToCSV = () => {
    const headers = ["Fecha", "Nombre", "Apellido", "Edad", "Documento", "Descripción", "Psicólogo"];
    const rows = patients.map(p => [
      p.fecha,
      p.nombre,
      p.apellido,
      p.edad,
      p.documentoIdentidad,
      `"${p.descripcion}"`, // Quote to handle commas in description
      p.psicologo
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
      + [headers.join(','), ...rows.map(e => e.join(','))].join('\n');

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "matriz_pacientes.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-6 max-w-6xl mx-auto">
      <header className="flex justify-between items-center mb-8">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Matriz de Pacientes</h2>
          <p className="text-gray-500 mt-1">Registra nuevos pacientes usando lenguaje natural.</p>
        </div>
        <button 
          onClick={exportToCSV}
          className="flex items-center gap-2 bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded-lg font-medium transition-colors shadow-sm"
        >
          <FileSpreadsheet size={18} />
          Exportar CSV
        </button>
      </header>

      {/* Input Section */}
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-200">
        <label className="block text-sm font-semibold text-gray-700 mb-2">
          Entrada Rápida
        </label>
        <div className="relative">
          <textarea
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            placeholder="Ej: Laura nunez, 32, 40200564348, separacion, Dra Aurora"
            className="w-full h-32 p-4 border border-gray-300 rounded-xl focus:ring-2 focus:ring-teal-500 focus:border-teal-500 transition-all resize-none text-gray-700"
          />
          <button
            onClick={handleProcess}
            disabled={isProcessing || !inputText}
            className={`absolute bottom-4 right-4 flex items-center gap-2 px-4 py-2 rounded-lg font-medium text-white transition-all ${
              isProcessing || !inputText 
                ? 'bg-gray-300 cursor-not-allowed' 
                : 'bg-teal-600 hover:bg-teal-700 shadow-md hover:shadow-lg'
            }`}
          >
            {isProcessing ? (
              <>
                <Loader2 size={18} className="animate-spin" />
                Procesando...
              </>
            ) : (
              <>
                <Sparkles size={18} />
                Procesar con IA
              </>
            )}
          </button>
        </div>
        {error && (
          <p className="text-red-500 text-sm mt-2">{error}</p>
        )}
      </div>

      {/* Table Section */}
      <div className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm text-gray-600">
            <thead className="bg-gray-50 border-b border-gray-200 text-xs uppercase font-semibold text-gray-500 tracking-wider">
              <tr>
                <th className="px-6 py-4">Fecha</th>
                <th className="px-6 py-4">Nombre Completo</th>
                <th className="px-6 py-4">Edad</th>
                <th className="px-6 py-4">Documento</th>
                <th className="px-6 py-4">Motivo</th>
                <th className="px-6 py-4">Psicólogo</th>
                <th className="px-6 py-4 text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {patients.length === 0 ? (
                <tr>
                  <td colSpan={7} className="px-6 py-12 text-center text-gray-400">
                    No hay pacientes registrados hoy. Usa la caja de arriba para añadir uno.
                  </td>
                </tr>
              ) : (
                patients.map((patient) => (
                  <tr key={patient.id} className="hover:bg-gray-50 transition-colors">
                    <td className="px-6 py-4 whitespace-nowrap">{patient.fecha}</td>
                    <td className="px-6 py-4 font-medium text-gray-900">
                      {patient.nombre} {patient.apellido}
                    </td>
                    <td className="px-6 py-4">{patient.edad}</td>
                    <td className="px-6 py-4 font-mono text-xs">{patient.documentoIdentidad}</td>
                    <td className="px-6 py-4 max-w-xs truncate" title={patient.descripcion}>
                      {patient.descripcion}
                    </td>
                    <td className="px-6 py-4">
                      <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-100 text-blue-800">
                        {patient.psicologo}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <button 
                        onClick={() => onDeletePatient(patient.id)}
                        className="text-gray-400 hover:text-red-500 transition-colors"
                      >
                        <Trash2 size={16} />
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { parseNotebookEntry } from '../services/geminiService';
import { Task, CalendarEvent } from '../types';
import { Sparkles, CheckCircle2, Calendar, Clock, Loader2, ArrowRight } from 'lucide-react';

interface DigitalNotebookProps {
  tasks: Task[];
  events: CalendarEvent[];
  onAddTasks: (tasks: Task[]) => void;
  onAddEvents: (events: CalendarEvent[]) => void;
  onToggleTask: (id: string) => void;
}

export const DigitalNotebook: React.FC<DigitalNotebookProps> = ({ tasks, events, onAddTasks, onAddEvents, onToggleTask }) => {
  const [inputText, setInputText] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);

  const handleProcess = async () => {
    if (!inputText.trim()) return;

    setIsProcessing(true);
    try {
      const result = await parseNotebookEntry(inputText);
      if (result) {
        const newTasks: Task[] = result.tasks.map(t => ({
          id: crypto.randomUUID(),
          title: t.title,
          isDone: false,
          priority: t.priority
        }));

        const newEvents: CalendarEvent[] = result.events.map(e => ({
          id: crypto.randomUUID(),
          title: e.title,
          date: e.date,
          time: e.time,
          description: e.description
        }));

        onAddTasks(newTasks);
        onAddEvents(newEvents);
        setInputText('');
      }
    } catch (error) {
      console.error(error);
      alert("Error al procesar la nota.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8 h-[calc(100vh-8rem)]">
      {/* Input Column */}
      <div className="flex flex-col gap-6">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Notebook Digital</h2>
          <p className="text-gray-500 mt-1">Escribe notas rápidas, la IA organizará tu agenda.</p>
        </div>

        <div className="bg-white p-1 rounded-2xl shadow-sm border border-gray-200 flex-1 flex flex-col">
           <textarea
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            placeholder="Ej: Tengo que llamar a Juan mañana a las 3pm, pagar la factura de luz y agendar cita con María el viernes..."
            className="w-full flex-1 p-6 rounded-xl focus:outline-none resize-none text-gray-700 text-lg placeholder:text-gray-300"
          />
          <div className="p-4 flex justify-between items-center border-t border-gray-100 bg-gray-50 rounded-b-xl">
             <span className="text-xs text-gray-400 font-medium">Detecta Tareas y Eventos Automáticamente</span>
             <button
              onClick={handleProcess}
              disabled={isProcessing || !inputText}
              className={`flex items-center gap-2 px-5 py-2.5 rounded-xl font-semibold text-white transition-all ${
                isProcessing || !inputText 
                  ? 'bg-gray-300 cursor-not-allowed' 
                  : 'bg-indigo-600 hover:bg-indigo-700 shadow-md hover:shadow-indigo-200'
              }`}
            >
              {isProcessing ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} />}
              Organizar
            </button>
          </div>
        </div>
      </div>

      {/* Output Column */}
      <div className="flex flex-col gap-6 overflow-hidden">

        {/* Google Tasks Simulation */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-200 flex-1 flex flex-col overflow-hidden">
          <div className="px-6 py-4 border-b border-gray-100 bg-gray-50 flex items-center justify-between">
            <div className="flex items-center gap-2">
               <div className="w-8 h-8 rounded-full bg-blue-100 flex items-center justify-center text-blue-600">
                 <CheckCircle2 size={18} />
               </div>
               <h3 className="font-semibold text-gray-800">Tareas (Google Tasks)</h3>
            </div>
            <span className="text-xs font-mono bg-white border border-gray-200 px-2 py-1 rounded text-gray-500">{tasks.filter(t => !t.isDone).length} pendientes</span>
          </div>
          <div className="p-4 overflow-y-auto flex-1 space-y-2">
            {tasks.length === 0 && (
              <p className="text-center text-gray-400 text-sm mt-8">No hay tareas pendientes.</p>
            )}
            {tasks.map(task => (
              <div key={task.id} className="group flex items-center gap-3 p-3 hover:bg-gray-50 rounded-lg transition-colors border border-transparent hover:border-gray-100">
                <button 
                  onClick={() => onToggleTask(task.id)}
                  className={`flex-shrink-0 w-5 h-5 rounded-full border-2 flex items-center justify-center transition-colors ${
                    task.isDone ? 'bg-blue-500 border-blue-500 text-white' : 'border-gray-300 hover:border-blue-400'
                  }`}
                >
                  {task.isDone && <CheckCircle2 size={12} />}
                </button>
                <span className={`flex-1 text-sm ${task.isDone ? 'text-gray-400 line-through' : 'text-gray-700'}`}>
                  {task.title}
                </span>
                <span className={`text-[10px] font-bold px-2 py-1 rounded-full uppercase ${
                  task.priority === 'High' ? 'bg-red-50 text-red-600' : 
                  task.priority === 'Medium' ? 'bg-yellow-50 text-yellow-600' : 'bg-gray-100 text-gray-500'
                }`}>
                  {task.priority}
                </span>
              </div>
            ))}
          </div>
        </div>

        {/* Google Calendar Simulation */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-200 flex-1 flex flex-col overflow-hidden">
          <div className="px-6 py-4 border-b border-gray-100 bg-gray-50 flex items-center gap-2">
             <div className="w-8 h-8 rounded-full bg-orange-100 flex items-center justify-center text-orange-600">
               <Calendar size={18} />
             </div>
             <h3 className="font-semibold text-gray-800">Eventos (Calendar)</h3>
          </div>
          <div className="p-4 overflow-y-auto flex-1 space-y-3">
             {events.length === 0 && (
              <p className="text-center text-gray-400 text-sm mt-8">No hay eventos próximos.</p>
            )}
            {events.map(event => (
              <div key={event.id} className="flex gap-4 p-3 border border-gray-100 rounded-lg bg-white shadow-sm hover:shadow-md transition-shadow">
                <div className="flex-shrink-0 flex flex-col items-center justify-center bg-orange-50 text-orange-700 rounded-lg w-14 h-14">
                  <span className="text-xs font-bold uppercase">{new Date(event.date).toLocaleDateString('es-ES', { month: 'short' })}</span>
                  <span className="text-lg font-bold">{new Date(event.date).getDate()}</span>
                </div>
                <div>
                  <h4 className="font-medium text-gray-900 text-sm">{event.title}</h4>
                  <div className="flex items-center gap-2 text-xs text-gray-500 mt-1">
                    <Clock size={12} />
                    {event.time}
                  </div>
                  {event.description && (
                    <p className="text-xs text-gray-400 mt-1 line-clamp-1">{event.description}</p>
                  )}
                </div>
              </div>
            ))}
          </div>
        </div>

      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { PatientManager } from './components/PatientManager';
import { DigitalNotebook } from './components/DigitalNotebook';
import { Dashboard } from './components/Dashboard';
import { Patient, Task, CalendarEvent, ViewState } from './types';
import { Settings as SettingsIcon, AlertCircle } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);

  // Local State Mock Databases
  const [patients, setPatients] = useState<Patient[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [events, setEvents] = useState<CalendarEvent[]>([]);

  // API Key handling state
  const [isApiKeySet, setIsApiKeySet] = useState(false);

  useEffect(() => {
    // Check if API Key is already in environment (passed via build process) or needs checking
    if (process.env.API_KEY) {
      setIsApiKeySet(true);
    }
  }, []);

  const handleAddPatient = (patient: Patient) => {
    setPatients(prev => [patient, ...prev]);
  };

  const handleDeletePatient = (id: string) => {
    setPatients(prev => prev.filter(p => p.id !== id));
  };

  const handleAddTasks = (newTasks: Task[]) => {
    setTasks(prev => [...prev, ...newTasks]);
  };

  const handleAddEvents = (newEvents: CalendarEvent[]) => {
    setEvents(prev => [...prev, ...newEvents]);
  };

  const handleToggleTask = (id: string) => {
    setTasks(prev => prev.map(t => t.id === id ? { ...t, isDone: !t.isDone } : t));
  };

  return (
    <div className="flex h-screen bg-[#F8FAFC]">
      <Sidebar currentView={currentView} onChangeView={setCurrentView} />

      <main className="flex-1 overflow-auto p-8 relative">
        {/* API Key Warning Overlay */}
        {!process.env.API_KEY && (
           <div className="mb-6 bg-red-50 border border-red-200 rounded-lg p-4 flex items-start gap-3">
             <AlertCircle className="text-red-500 mt-0.5" />
             <div>
               <h4 className="font-bold text-red-700">Falta la API Key</h4>
               <p className="text-sm text-red-600">
                 Esta aplicación requiere una Google Gemini API Key para funcionar. 
                 En un entorno de producción, esto se configuraría en las variables de entorno.
                 <br />
                 <span className="font-mono text-xs mt-1 block bg-red-100 p-1 rounded w-fit">process.env.API_KEY is missing</span>
               </p>
             </div>
           </div>
        )}

        {currentView === ViewState.DASHBOARD && (
          <Dashboard 
            patients={patients}
            tasks={tasks}
            events={events}
            onChangeView={setCurrentView}
          />
        )}

        {currentView === ViewState.PATIENTS && (
          <PatientManager 
            patients={patients}
            onAddPatient={handleAddPatient}
            onDeletePatient={handleDeletePatient}
          />
        )}

        {currentView === ViewState.NOTEBOOK && (
          <DigitalNotebook 
            tasks={tasks}
            events={events}
            onAddTasks={handleAddTasks}
            onAddEvents={handleAddEvents}
            onToggleTask={handleToggleTask}
          />
        )}

        {currentView === ViewState.SETTINGS && (
          <div className="max-w-2xl mx-auto bg-white p-8 rounded-2xl shadow-sm border border-gray-100">
            <div className="flex items-center gap-3 mb-6 pb-6 border-b border-gray-100">
              <div className="w-12 h-12 bg-gray-100 rounded-full flex items-center justify-center text-gray-500">
                <SettingsIcon size={24} />
              </div>
              <div>
                <h2 className="text-xl font-bold text-gray-800">Configuración</h2>
                <p className="text-gray-500">Ajustes generales de la aplicación</p>
              </div>
            </div>

            <div className="space-y-6">
              <div>
