interface DigitalNotebookProps {
  tasks: Task[];
  events: CalendarEvent[];
  onAddTasks: (tasks: Task[]) => void;
  onAddEvents: (events: CalendarEvent[]) => void;
  onToggleTask: (id: string) => void;
}

export const DigitalNotebook: React.FC<DigitalNotebookProps> = ({ tasks, events, onAddTasks, onAddEvents, onToggleTask }) => {
  const [inputText, setInputText] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [manualPriority, setManualPriority] = useState<'Auto' | 'High' | 'Medium' | 'Low'>('Auto');

  const handleProcess = async () => {
    if (!inputText.trim()) return;

    setIsProcessing(true);
    try {
      const result = await parseNotebookEntry(inputText);
      if (result) {
        const newTasks: Task[] = result.tasks.map(t => ({
          id: crypto.randomUUID(),
          title: t.title,
          isDone: false,
          // Use manual priority if set, otherwise fallback to AI detected priority
          priority: manualPriority !== 'Auto' ? manualPriority : t.priority
        }));

        const newEvents: CalendarEvent[] = result.events.map(e => ({
          id: crypto.randomUUID(),
          title: e.title,
          date: e.date,
          time: e.time,
          description: e.description
        }));

        onAddTasks(newTasks);
        onAddEvents(newEvents);
        setInputText('');
        setManualPriority('Auto'); // Reset to Auto after adding
      }
    } catch (error) {
      console.error(error);
      alert("Error al procesar la nota.");
    } finally {
      setIsProcessing(false);
    }
  };

  const getPriorityColor = (p: string) => {
    switch(p) {
      case 'High': return 'text-red-500';
      case 'Medium': return 'text-yellow-500';
      case 'Low': return 'text-gray-500';
      default: return 'text-indigo-500';
