import { GoogleGenAI, Type } from "@google/genai";
import { NotebookAnalysisResult, Patient } from "../types";

const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing. Please set it in the Settings.");
  }
  return new GoogleGenAI({ apiKey });
};

export const parsePatientData = async (inputText: string): Promise<Omit<Patient, 'id' | 'fecha'> | null> => {
  try {
    const ai = getAiClient();
    const modelId = "gemini-3-flash-preview"; 

    const response = await ai.models.generateContent({
      model: modelId,
      contents: `Extract patient information from the following text to populate a spreadsheet. 
      The input text is likely unstructured like "Laura nunez, 32, 40200564348, separacion, aurora".

      Input Text: "${inputText}"

      Rules:
      - Split names into 'nombre' and 'apellido' if possible.
      - 'documentoIdentidad' is the ID number.
      - 'descripcion' is the reason for consultation or problem.
      - 'psicologo' is the name of the doctor/therapist.
      - 'tipo': Determine if the patient is 'Nuevo' (New) or 'Regular' (Regular). If context implies first time (e.g., 'primera vez', 'evaluación', 'apertura'), use 'Nuevo'. If context implies follow-up (e.g., 'control', 'seguimiento', 'cita semanal'), use 'Regular'. Default to 'Nuevo' if unsure.
      - If a field is missing, return an empty string or 0.
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            nombre: { type: Type.STRING },
            apellido: { type: Type.STRING },
            edad: { type: Type.NUMBER },
            documentoIdentidad: { type: Type.STRING },
            descripcion: { type: Type.STRING },
            psicologo: { type: Type.STRING },
            tipo: { type: Type.STRING, enum: ["Nuevo", "Regular"] },
          },
          required: ["nombre", "apellido", "edad", "documentoIdentidad", "descripcion", "psicologo", "tipo"],
        },
      },
    });

    if (response.text) {
      return JSON.parse(response.text) as Omit<Patient, 'id' | 'fecha'>;
    }
    return null;
  } catch (error) {
    console.error("Error parsing patient data:", error);
    throw error;
  }
};

export const parseNotebookEntry = async (inputText: string): Promise<NotebookAnalysisResult | null> => {
  try {
    const ai = getAiClient();
    const modelId = "gemini-3-flash-preview";

    const response = await ai.models.generateContent({
      model: modelId,
      contents: `Analyze the following notebook entry and extract actionable items.
      Separate them into 'tasks' (to-do items) and 'events' (appointments with specific times/dates).

      Input Text: "${inputText}"

      Date Reference: Today is ${new Date().toLocaleDateString()}.
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            tasks: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  priority: { type: Type.STRING, enum: ["High", "Medium", "Low"] },
                }
              }
            },
            events: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  date: { type: Type.STRING, description: "YYYY-MM-DD format" },
                  time: { type: Type.STRING, description: "HH:MM format" },
                  description: { type: Type.STRING },
                }
              }
            }
          }
        },
      },
    });

    if (response.text) {
      return JSON.parse(response.text) as NotebookAnalysisResult;
    }
    return null;
  } catch (error) {
    console.error("Error analyzing notebook:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { parsePatientData } from '../services/geminiService';
import { Patient } from '../types';
import { Sparkles, FileSpreadsheet, Download, Copy, Trash2, Plus, Loader2, Search, ChevronLeft, ChevronRight, UserPlus, UserCheck } from 'lucide-react';

interface PatientManagerProps {
  patients: Patient[];
  onAddPatient: (patient: Patient) => void;
  onDeletePatient: (id: string) => void;
}

export const PatientManager: React.FC<PatientManagerProps> = ({ patients, onAddPatient, onDeletePatient }) => {
  const [inputText, setInputText] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10;

  // Reset pagination when search changes
  useEffect(() => {
    setCurrentPage(1);
  }, [searchTerm, patients.length]);

  const handleProcess = async () => {
    if (!inputText.trim()) return;

    setIsProcessing(true);
    setError(null);
    try {
      const parsedData = await parsePatientData(inputText);
      if (parsedData) {
        const newPatient: Patient = {
          id: crypto.randomUUID(),
          fecha: new Date().toLocaleDateString('es-ES'),
          ...parsedData
        };
        onAddPatient(newPatient);
        setInputText(''); // Clear input on success
      } else {
        setError('No se pudo interpretar la información. Intenta ser más claro.');
      }
    } catch (err: any) {
      setError(err.message || 'Error al conectar con la IA.');
    } finally {
      setIsProcessing(false);
    }
  };

  const exportToCSV = () => {
    const headers = ["Fecha", "Nombre", "Apellido", "Edad", "Documento", "Descripción", "Psicólogo", "Tipo"];
    const rows = patients.map(p => [
      p.fecha,
      p.nombre,
      p.apellido,
      p.edad,
      p.documentoIdentidad,
      `"${p.descripcion}"`, // Quote to handle commas in description
      p.psicologo,
      p.tipo
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
      + [headers.join(','), ...rows.map(e => e.join(','))].join('\n');

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "matriz_pacientes.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Logic to filter patients
  const filteredPatients = patients.filter(patient => {
    const term = searchTerm.toLowerCase();
    const fullName = `${patient.nombre} ${patient.apellido}`.toLowerCase();

    return (
      fullName.includes(term) ||
      patient.fecha.includes(term) ||
      patient.psicologo.toLowerCase().includes(term) ||
      patient.documentoIdentidad.includes(term) ||
      patient.tipo.toLowerCase().includes(term)
    );
  });

  // Pagination Logic
  const totalPages = Math.ceil(filteredPatients.length / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const displayedPatients = filteredPatients.slice(startIndex, startIndex + itemsPerPage);

  const goToPreviousPage = () => {
    setCurrentPage(prev => Math.max(prev - 1, 1));
  };

  const goToNextPage = () => {
    setCurrentPage(prev => Math.min(prev + 1, totalPages));
  };

  return (
    <div className="space-y-6 max-w-6xl mx-auto">
      <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-8 gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Matriz de Pacientes</h2>
          <p className="text-gray-500 mt-1">Registra nuevos pacientes usando lenguaje natural.</p>
        </div>
        <button 
          onClick={exportToCSV}
          className="w-full sm:w-auto flex items-center justify-center gap-2 bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded-lg font-medium transition-colors shadow-sm"
        >
          <FileSpreadsheet size={18} />
          Exportar CSV
        </button>
      </header>

      {/* Input Section */}
      <div className="bg-white p-4 md:p-6 rounded-2xl shadow-sm border border-gray-200">
        <label className="block text-sm font-semibold text-gray-700 mb-2">
          Entrada Rápida
        </label>
        <div className="relative">
          <textarea
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            placeholder="Ej: Laura nunez, 32, 40200564348, separacion, Dra Aurora (primera vez)"
            className="w-full h-32 p-4 bg-gray-800 border border-gray-700 rounded-xl focus:ring-2 focus:ring-teal-500 focus:border-teal-500 transition-all resize-none text-white placeholder-gray-400 pb-16"
          />
          <button
            onClick={handleProcess}
            disabled={isProcessing || !inputText}
            className={`absolute bottom-4 right-4 flex items-center gap-2 px-4 py-2 rounded-lg font-medium text-white transition-all ${
              isProcessing || !inputText 
                ? 'bg-gray-600 cursor-not-allowed' 
                : 'bg-teal-600 hover:bg-teal-700 shadow-md hover:shadow-lg'
            }`}
          >
            {isProcessing ? (
              <>
                <Loader2 size={18} className="animate-spin" />
                <span className="hidden sm:inline">Procesando...</span>
              </>
            ) : (
              <>
                <Sparkles size={18} />
                <span className="hidden sm:inline">Procesar con IA</span>
                <span className="sm:hidden">Procesar</span>
              </>
            )}
          </button>
        </div>
        {error && (
          <p className="text-red-500 text-sm mt-2">{error}</p>
        )}
      </div>

      {/* Filter & Table Section */}
      <div className="space-y-4">
        {/* Search Bar */}
        <div className="relative">
          <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
            <Search className="h-5 w-5 text-gray-400" />
          </div>
          <input
            type="text"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="block w-full pl-10 pr-3 py-2 border border-gray-200 rounded-xl leading-5 bg-white placeholder-gray-400 focus:outline-none focus:ring-1 focus:ring-teal-500 focus:border-teal-500 sm:text-sm shadow-sm"
            placeholder="Buscar por nombre, fecha, psicólogo, tipo..."
          />
        </div>

        {/* Table */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left text-sm text-gray-600">
              <thead className="bg-gray-50 border-b border-gray-200 text-xs uppercase font-semibold text-gray-500 tracking-wider">
                <tr>
                  <th className="px-6 py-4">Fecha</th>
                  <th className="px-6 py-4">Nombre Completo</th>
                  <th className="px-6 py-4">Edad</th>
                  <th className="px-6 py-4">Documento</th>
                  <th className="px-6 py-4">Motivo</th>
                  <th className="px-6 py-4">Psicólogo</th>
                  <th className="px-6 py-4">Tipo</th>
                  <th className="px-6 py-4 text-right">Acciones</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {filteredPatients.length === 0 ? (
                  <tr>
                    <td colSpan={8} className="px-6 py-12 text-center text-gray-400">
                      {searchTerm ? (
                        <span>No se encontraron resultados para "{searchTerm}"</span>
                      ) : (
                        <span>No hay pacientes registrados.</span>
                      )}
                    </td>
                  </tr>
                ) : (
                  displayedPatients.map((patient) => (
                    <tr key={patient.id} className="hover:bg-gray-50 transition-colors">
                      <td className="px-6 py-4 whitespace-nowrap">{patient.fecha}</td>
                      <td className="px-6 py-4 font-medium text-gray-900 whitespace-nowrap">
                        {patient.nombre} {patient.apellido}
                      </td>
                      <td className="px-6 py-4">{patient.edad}</td>
                      <td className="px-6 py-4 font-mono text-xs">{patient.documentoIdentidad}</td>
                      <td className="px-6 py-4 max-w-xs truncate" title={patient.descripcion}>
                        {patient.descripcion}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-100 text-blue-800">
                          {patient.psicologo}
                        </span>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <span className={`inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full text-xs font-medium ${
                          patient.tipo === 'Nuevo' 
                            ? 'bg-green-100 text-green-700' 
                            : 'bg-gray-100 text-gray-600'
                        }`}>
                          {patient.tipo === 'Nuevo' ? <UserPlus size={12} /> : <UserCheck size={12} />}
                          {patient.tipo}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <button 
                          onClick={() => onDeletePatient(patient.id)}
                          className="text-gray-400 hover:text-red-500 transition-colors"
                        >
                          <Trash2 size={16} />
                        </button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>

          {/* Pagination Controls */}
          {filteredPatients.length > 0 && (
            <div className="bg-gray-50 px-6 py-4 border-t border-gray-200 flex items-center justify-between">
              <div className="text-sm text-gray-500">
                Mostrando <span className="font-medium">{startIndex + 1}</span> a <span className="font-medium">{Math.min(startIndex + itemsPerPage, filteredPatients.length)}</span> de <span className="font-medium">{filteredPatients.length}</span> pacientes
              </div>
              <div className="flex items-center gap-2">
                <button
                  onClick={goToPreviousPage}
                  disabled={currentPage === 1}
                  className={`p-2 rounded-lg border border-gray-300 transition-all ${
                    currentPage === 1 
                      ? 'bg-gray-100 text-gray-400 cursor-not-allowed' 
                      : 'bg-white text-gray-600 hover:bg-gray-50 hover:border-gray-400'
                  }`}
                >
                  <ChevronLeft size={16} />
                </button>
                <div className="flex items-center gap-1 px-2">
                  <span className="text-sm font-medium text-gray-700">Página {currentPage}</span>
                  <span className="text-sm text-gray-400">/ {totalPages || 1}</span>
                </div>
                <button
                  onClick={goToNextPage}
                  disabled={currentPage === totalPages || totalPages === 0}
                  className={`p-2 rounded-lg border border-gray-300 transition-all ${
                    currentPage === totalPages || totalPages === 0
                      ? 'bg-gray-100 text-gray-400 cursor-not-allowed' 
                      : 'bg-white text-gray-600 hover:bg-gray-50 hover:border-gray-400'
                  }`}
                >
                  <ChevronRight size={16} />
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

