        </div>
        <div className="text-left md:text-right">
           <p className="text-sm font-medium text-gray-400 uppercase tracking-wide">Fecha Actual</p>
           <p className="text-lg md:text-xl font-semibold text-gray-700 capitalize">{new Date().toLocaleDateString('es-ES', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</p>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-6">
