              <div className="bg-blue-50 p-4 rounded-lg border border-blue-100 text-sm text-blue-800 mt-6">
                <p className="mb-2"><strong>Instrucciones:</strong></p>
                <ol className="list-decimal pl-4 space-y-1 text-xs">
