import { Sparkles, FileSpreadsheet, Trash2, Loader2, Search, ChevronLeft, ChevronRight, UserPlus, UserCheck, CloudUpload } from 'lucide-react';

interface PatientManagerProps {
  patients: Patient[];
  onAddPatient: (patient: Patient) => void;
  onDeletePatient: (id: string) => void;
  isAuthenticated: boolean;
  spreadsheetId: string;
}

export const PatientManager: React.FC<PatientManagerProps> = ({ patients, onAddPatient, onDeletePatient, isAuthenticated, spreadsheetId }) => {
  const [inputText, setInputText] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [statusMessage, setStatusMessage] = useState<{type: 'error' | 'success', text: string} | null>(null);

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10;

  useEffect(() => {
    setCurrentPage(1);
  }, [searchTerm, patients.length]);

  const handleProcess = async () => {
    if (!inputText.trim()) return;

    setIsProcessing(true);
    setStatusMessage(null);
    try {
      // 1. Parse with Gemini
      const parsedData = await parsePatientData(inputText);

      if (parsedData) {
        const newPatient: Patient = {
          id: crypto.randomUUID(),
          fecha: new Date().toLocaleDateString('es-ES'),
          ...parsedData
        };

        // 2. Send to Google Sheets if configured
        if (isAuthenticated && spreadsheetId) {
          try {
             await appendPatientToSheet(spreadsheetId, newPatient);
             // 3. Update local UI only if Sheet update was successful (or to reflect optimistic UI)
             onAddPatient(newPatient);
             setInputText('');
             setStatusMessage({ type: 'success', text: 'Paciente registrado en Google Sheets y localmente.' });
          } catch (sheetError) {
             console.error(sheetError);
             setStatusMessage({ type: 'error', text: 'Datos analizados, pero falló al guardar en Google Sheet. Revisa permisos/ID.' });
             // Still add locally so data isn't lost? Let's strictly require Sheet success for "Real Integration" feel, 
             // or add locally and warn. Let's add locally to be safe.
             onAddPatient(newPatient);
          }
        } else {
           // Offline/No-Auth mode
           onAddPatient(newPatient);
           setInputText('');
           setStatusMessage({ type: 'success', text: 'Paciente registrado localmente (Google Sheets no conectado).' });
        }

      } else {
        setStatusMessage({ type: 'error', text: 'No se pudo interpretar la información. Intenta ser más claro.' });
      }
    } catch (err: any) {
      setStatusMessage({ type: 'error', text: err.message || 'Error al procesar.' });
    } finally {
      setIsProcessing(false);
    }
  };

  const exportToCSV = () => {
    const headers = ["Fecha", "Nombre", "Apellido", "Edad", "Documento", "Descripción", "Psicólogo", "Tipo"];
    const rows = patients.map(p => [
      p.fecha,
      p.nombre,
      p.apellido,
      p.edad,
      p.documentoIdentidad,
      `"${p.descripcion}"`,
      p.psicologo,
      p.tipo
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
      + [headers.join(','), ...rows.map(e => e.join(','))].join('\n');

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "matriz_pacientes.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const filteredPatients = patients.filter(patient => {
    const term = searchTerm.toLowerCase();
    const fullName = `${patient.nombre} ${patient.apellido}`.toLowerCase();
    return (
      fullName.includes(term) ||
      patient.fecha.includes(term) ||
      patient.psicologo.toLowerCase().includes(term) ||
      patient.documentoIdentidad.includes(term) ||
      patient.tipo.toLowerCase().includes(term)
    );
  });

  const totalPages = Math.ceil(filteredPatients.length / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const displayedPatients = filteredPatients.slice(startIndex, startIndex + itemsPerPage);

  const goToPreviousPage = () => setCurrentPage(prev => Math.max(prev - 1, 1));
  const goToNextPage = () => setCurrentPage(prev => Math.min(prev + 1, totalPages));

  return (
    <div className="space-y-6 max-w-6xl mx-auto">
      <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-8 gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Matriz de Pacientes</h2>
          <div className="flex items-center gap-2 mt-1">
             <p className="text-gray-500">Registra pacientes en tu Google Sheet.</p>
             {isAuthenticated && spreadsheetId ? (
               <span className="text-xs bg-green-100 text-green-700 px-2 py-0.5 rounded-full flex items-center gap-1">
                 <CloudUpload size={10} /> Conectado a Sheets
               </span>
             ) : (
               <span className="text-xs bg-gray-100 text-gray-500 px-2 py-0.5 rounded-full">Modo Local</span>
             )}
          </div>
        </div>
        <button 
          onClick={exportToCSV}
          className="w-full sm:w-auto flex items-center justify-center gap-2 bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded-lg font-medium transition-colors shadow-sm"
        >
          <FileSpreadsheet size={18} />
          Exportar CSV
        </button>
      </header>

      {/* Input Section */}
      <div className="bg-white p-4 md:p-6 rounded-2xl shadow-sm border border-gray-200">
        <label className="block text-sm font-semibold text-gray-700 mb-2">
          Entrada Rápida
        </label>
        <div className="relative">
          <textarea
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            placeholder="Ej: Laura nunez, 32, 40200564348, separacion, Dra Aurora (primera vez)"
            className="w-full h-32 p-4 bg-gray-800 border border-gray-700 rounded-xl focus:ring-2 focus:ring-teal-500 focus:border-teal-500 transition-all resize-none text-white placeholder-gray-400 pb-16"
          />
          <button
            onClick={handleProcess}
            disabled={isProcessing || !inputText}
            className={`absolute bottom-4 right-4 flex items-center gap-2 px-4 py-2 rounded-lg font-medium text-white transition-all ${
              isProcessing || !inputText 
                ? 'bg-gray-600 cursor-not-allowed' 
                : 'bg-teal-600 hover:bg-teal-700 shadow-md hover:shadow-lg'
            }`}
          >
            {isProcessing ? (
              <>
                <Loader2 size={18} className="animate-spin" />
                <span className="hidden sm:inline">Procesando...</span>
              </>
            ) : (
              <>
                <Sparkles size={18} />
                <span className="hidden sm:inline">Procesar y Guardar</span>
                <span className="sm:hidden">Procesar</span>
              </>
            )}
          </button>
        </div>
        {statusMessage && (
          <p className={`text-sm mt-2 ${statusMessage.type === 'error' ? 'text-red-500' : 'text-green-600'}`}>
            {statusMessage.text}
          </p>
        )}
      </div>

      {/* Filter & Table Section */}
      <div className="space-y-4">
        {/* Search Bar */}
        <div className="relative">
          <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
            <Search className="h-5 w-5 text-gray-400" />
          </div>
          <input
            type="text"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="block w-full pl-10 pr-3 py-2 border border-gray-200 rounded-xl leading-5 bg-white placeholder-gray-400 focus:outline-none focus:ring-1 focus:ring-teal-500 focus:border-teal-500 sm:text-sm shadow-sm"
            placeholder="Buscar por nombre, fecha, psicólogo, tipo..."
          />
        </div>

        {/* Table */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left text-sm text-gray-600">
              <thead className="bg-gray-50 border-b border-gray-200 text-xs uppercase font-semibold text-gray-500 tracking-wider">
                <tr>
                  <th className="px-6 py-4">Fecha</th>
                  <th className="px-6 py-4">Nombre Completo</th>
                  <th className="px-6 py-4">Edad</th>
                  <th className="px-6 py-4">Documento</th>
                  <th className="px-6 py-4">Motivo</th>
                  <th className="px-6 py-4">Psicólogo</th>
                  <th className="px-6 py-4">Tipo</th>
                  <th className="px-6 py-4 text-right">Acciones</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {filteredPatients.length === 0 ? (
                  <tr>
                    <td colSpan={8} className="px-6 py-12 text-center text-gray-400">
                      {searchTerm ? <span>No se encontraron resultados.</span> : <span>No hay pacientes registrados.</span>}
                    </td>
                  </tr>
                ) : (
                  displayedPatients.map((patient) => (
                    <tr key={patient.id} className="hover:bg-teal-50/40 transition-colors duration-200">
                      <td className="px-6 py-4 whitespace-nowrap">{patient.fecha}</td>
                      <td className="px-6 py-4 font-bold text-base text-gray-900 whitespace-nowrap">
                        {patient.nombre} {patient.apellido}
                      </td>
                      <td className="px-6 py-4">{patient.edad}</td>
                      <td className="px-6 py-4 font-mono text-xs text-gray-500">{patient.documentoIdentidad}</td>
                      <td className="px-6 py-4 max-w-xs truncate text-gray-500" title={patient.descripcion}>
                        {patient.descripcion}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-100 text-blue-800">
                          {patient.psicologo}
                        </span>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <span className={`inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full text-xs font-medium ${
                          patient.tipo === 'Nuevo' ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-600'
                        }`}>
                          {patient.tipo === 'Nuevo' ? <UserPlus size={12} /> : <UserCheck size={12} />}
                          {patient.tipo}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <button 
                          onClick={() => onDeletePatient(patient.id)}
                          className="text-gray-400 hover:text-red-500 transition-colors"
                        >
                          <Trash2 size={16} />
                        </button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>

          {/* Pagination Controls */}
          {filteredPatients.length > 0 && (
            <div className="bg-gray-50 px-6 py-4 border-t border-gray-200 flex items-center justify-between">
              <div className="text-sm text-gray-500">
                Mostrando <span className="font-medium">{startIndex + 1}</span> a <span className="font-medium">{Math.min(startIndex + itemsPerPage, filteredPatients.length)}</span> de <span className="font-medium">{filteredPatients.length}</span>
              </div>
              <div className="flex items-center gap-2">
                <button
                  onClick={goToPreviousPage}
                  disabled={currentPage === 1}
                  className={`p-2 rounded-lg border border-gray-300 transition-all ${currentPage === 1 ? 'bg-gray-100 text-gray-400' : 'bg-white hover:bg-gray-50'}`}
                >
                  <ChevronLeft size={16} />
                </button>
                <div className="flex items-center gap-1 px-2">
                  <span className="text-sm font-medium text-gray-700">{currentPage}</span>
                  <span className="text-sm text-gray-400">/ {totalPages || 1}</span>
                </div>
                <button
                  onClick={goToNextPage}
                  disabled={currentPage === totalPages || totalPages === 0}
                  className={`p-2 rounded-lg border border-gray-300 transition-all ${currentPage === totalPages ? 'bg-gray-100 text-gray-400' : 'bg-white hover:bg-gray-50'}`}
                >
                  <ChevronRight size={16} />
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { parseNotebookEntry } from '../services/geminiService';
import { createGoogleTask, createGoogleCalendarEvent } from '../services/googleApiService';
import { Task, CalendarEvent } from '../types';
import { Sparkles, CheckCircle2, Calendar, Clock, Loader2, Flag, Check } from 'lucide-react';

interface DigitalNotebookProps {
  tasks: Task[];
  events: CalendarEvent[];
  onAddTasks: (tasks: Task[]) => void;
  onAddEvents: (events: CalendarEvent[]) => void;
  onToggleTask: (id: string) => void;
  isAuthenticated: boolean;
}

export const DigitalNotebook: React.FC<DigitalNotebookProps> = ({ tasks, events, onAddTasks, onAddEvents, onToggleTask, isAuthenticated }) => {
  const [inputText, setInputText] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [manualPriority, setManualPriority] = useState<'Auto' | 'High' | 'Medium' | 'Low'>('Auto');

  const handleProcess = async () => {
    if (!inputText.trim()) return;

    setIsProcessing(true);
    try {
      // 1. Parse with Gemini
      const result = await parseNotebookEntry(inputText);

      if (result) {
        const newTasks: Task[] = result.tasks.map(t => ({
          id: crypto.randomUUID(),
          title: t.title,
          isDone: false,
          priority: manualPriority !== 'Auto' ? manualPriority : t.priority
        }));

        const newEvents: CalendarEvent[] = result.events.map(e => ({
          id: crypto.randomUUID(),
          title: e.title,
          date: e.date,
          time: e.time,
          description: e.description
        }));

        // 2. Real Integration: Send to Google
        if (isAuthenticated) {
          // Process Tasks
          for (const task of newTasks) {
            try {
              await createGoogleTask(task);
            } catch (e) {
              console.error("Failed to sync task", e);
            }
          }
          // Process Events
          for (const event of newEvents) {
            try {
              await createGoogleCalendarEvent(event);
            } catch (e) {
               console.error("Failed to sync event", e);
            }
          }
        }

        // 3. Update Local UI
        onAddTasks(newTasks);
        onAddEvents(newEvents);
        setInputText('');
        setManualPriority('Auto');
      }
    } catch (error) {
      console.error(error);
      alert("Error al procesar la nota.");
    } finally {
      setIsProcessing(false);
    }
  };

  const getPriorityColor = (p: string) => {
    switch(p) {
      case 'High': return 'text-red-500';
      case 'Medium': return 'text-yellow-500';
      case 'Low': return 'text-gray-500';
      default: return 'text-indigo-500';
    }
  };

  return (
    <div className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8 h-auto lg:h-[calc(100vh-8rem)]">
      {/* Input Column */}
      <div className="flex flex-col gap-6 h-full">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Notebook Digital</h2>
          <div className="flex items-center gap-2 mt-1">
             <p className="text-gray-500">Tus notas se sincronizan automáticamente.</p>
             {isAuthenticated ? (
               <span className="text-xs bg-green-100 text-green-700 px-2 py-0.5 rounded-full flex items-center gap-1">
                 <Check size={10} /> Sync On
               </span>
             ) : (
               <span className="text-xs bg-gray-100 text-gray-500 px-2 py-0.5 rounded-full">Sync Off</span>
             )}
          </div>
        </div>

        <div className="bg-white p-1 rounded-2xl shadow-sm border border-gray-200 flex flex-col min-h-[300px] lg:flex-1">
           <textarea
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            placeholder="Ej: Tengo que llamar a Juan mañana a las 3pm, pagar la factura de luz y agendar cita con María el viernes..."
            className="w-full flex-1 p-6 bg-gray-800 rounded-t-xl focus:outline-none resize-none text-white text-lg placeholder:text-gray-400 min-h-[200px]"
          />
          <div className="p-4 flex flex-col sm:flex-row gap-4 justify-between items-center border-t border-gray-100 bg-gray-50 rounded-b-xl">
             <div className="flex items-center gap-3 w-full sm:w-auto">
               <div className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-lg border border-gray-200 shadow-sm w-full sm:w-auto">
                  <Flag size={16} className={getPriorityColor(manualPriority)} />
                  <select
                    value={manualPriority}
                    onChange={(e) => setManualPriority(e.target.value as any)}
                    className="bg-transparent text-sm text-gray-700 font-medium focus:outline-none cursor-pointer w-full sm:w-auto"
                  >
                    <option value="Auto">Prioridad: Auto (IA)</option>
                    <option value="High">Prioridad: Alta</option>
                    <option value="Medium">Prioridad: Media</option>
                    <option value="Low">Prioridad: Baja</option>
                  </select>
               </div>
             </div>

             <button
              onClick={handleProcess}
              disabled={isProcessing || !inputText}
              className={`w-full sm:w-auto flex items-center justify-center gap-2 px-5 py-2.5 rounded-xl font-semibold text-white transition-all ${
                isProcessing || !inputText 
                  ? 'bg-gray-300 cursor-not-allowed' 
                  : 'bg-indigo-600 hover:bg-indigo-700 shadow-md hover:shadow-indigo-200'
              }`}
            >
              {isProcessing ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} />}
              Organizar & Sync
            </button>
          </div>
        </div>
      </div>

      {/* Output Column */}
      <div className="flex flex-col gap-6 h-full overflow-hidden">

        {/* Google Tasks */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-200 flex flex-col max-h-[400px] lg:max-h-none lg:flex-1 overflow-hidden">
          <div className="px-6 py-4 border-b border-gray-100 bg-gray-50 flex items-center justify-between">
            <div className="flex items-center gap-2">
               <div className="w-8 h-8 rounded-full bg-blue-100 flex items-center justify-center text-blue-600">
                 <CheckCircle2 size={18} />
               </div>
               <h3 className="font-semibold text-gray-800">Tareas (Google Tasks)</h3>
            </div>
            <span className="text-xs font-mono bg-white border border-gray-200 px-2 py-1 rounded text-gray-500">{tasks.filter(t => !t.isDone).length} pendientes</span>
          </div>
          <div className="p-4 overflow-y-auto flex-1 space-y-2">
            {tasks.length === 0 && (
              <p className="text-center text-gray-400 text-sm mt-8">No hay tareas pendientes.</p>
            )}
            {tasks.map(task => (
              <div key={task.id} className="group flex items-center gap-3 p-3 hover:bg-gray-50 rounded-lg transition-colors border border-transparent hover:border-gray-100">
                <button 
                  onClick={() => onToggleTask(task.id)}
                  className={`flex-shrink-0 w-5 h-5 rounded-full border-2 flex items-center justify-center transition-colors ${
                    task.isDone ? 'bg-blue-500 border-blue-500 text-white' : 'border-gray-300 hover:border-blue-400'
                  }`}
                >
                  {task.isDone && <CheckCircle2 size={12} />}
                </button>
                <span className={`flex-1 text-sm ${task.isDone ? 'text-gray-400 line-through' : 'text-gray-700'}`}>
                  {task.title}
                </span>
                <span className={`text-[10px] font-bold px-2 py-1 rounded-full uppercase ${
                  task.priority === 'High' ? 'bg-red-50 text-red-600' : 
                  task.priority === 'Medium' ? 'bg-yellow-50 text-yellow-600' : 'bg-gray-100 text-gray-500'
                }`}>
                  {task.priority}
                </span>
              </div>
            ))}
          </div>
        </div>

        {/* Google Calendar */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-200 flex flex-col max-h-[400px] lg:max-h-none lg:flex-1 overflow-hidden">
          <div className="px-6 py-4 border-b border-gray-100 bg-gray-50 flex items-center gap-2">
             <div className="w-8 h-8 rounded-full bg-orange-100 flex items-center justify-center text-orange-600">
               <Calendar size={18} />
             </div>
             <h3 className="font-semibold text-gray-800">Eventos (Calendar)</h3>
          </div>
          <div className="p-4 overflow-y-auto flex-1 space-y-3">
             {events.length === 0 && (
              <p className="text-center text-gray-400 text-sm mt-8">No hay eventos próximos.</p>
            )}
            {events.map(event => (
              <div key={event.id} className="flex gap-4 p-3 border border-gray-100 rounded-lg bg-white shadow-sm hover:shadow-md transition-shadow">
                <div className="flex-shrink-0 flex flex-col items-center justify-center bg-orange-50 text-orange-700 rounded-lg w-14 h-14">
                  <span className="text-xs font-bold uppercase">{new Date(event.date).toLocaleDateString('es-ES', { month: 'short' })}</span>
                  <span className="text-lg font-bold">{new Date(event.date).getDate()}</span>
                </div>
                <div>
                  <h4 className="font-medium text-gray-900 text-sm">{event.title}</h4>
                  <div className="flex items-center gap-2 text-xs text-gray-500 mt-1">
                    <Clock size={12} />
                    {event.time}
                  </div>
                  {event.description && (
                    <p className="text-xs text-gray-400 mt-1 line-clamp-1">{event.description}</p>
                  )}
                </div>
              </div>
            ))}
          </div>
        </div>

      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { parsePatientData } from '../services/geminiService';
import { appendPatientToSheet } from '../services/googleApiService';
import { Patient } from '../types';
import { Sparkles, FileSpreadsheet, Trash2, Loader2, Search, ChevronLeft, ChevronRight, UserPlus, UserCheck, CloudUpload, X } from 'lucide-react';

interface PatientManagerProps {
  patients: Patient[];
  onAddPatient: (patient: Patient) => void;
  onDeletePatient: (id: string) => void;
  isAuthenticated: boolean;
  spreadsheetId: string;
}

export const PatientManager: React.FC<PatientManagerProps> = ({ patients, onAddPatient, onDeletePatient, isAuthenticated, spreadsheetId }) => {
  const [inputText, setInputText] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [statusMessage, setStatusMessage] = useState<{type: 'error' | 'success', text: string} | null>(null);

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10;

  useEffect(() => {
    setCurrentPage(1);
  }, [searchTerm, patients.length]);

  const handleProcess = async () => {
    if (!inputText.trim()) return;

    setIsProcessing(true);
    setStatusMessage(null);
    try {
      // 1. Parse with Gemini
      const parsedData = await parsePatientData(inputText);

      if (parsedData) {
        const newPatient: Patient = {
          id: crypto.randomUUID(),
          fecha: new Date().toLocaleDateString('es-ES'),
          ...parsedData
        };

        // 2. Send to Google Sheets if configured
        if (isAuthenticated && spreadsheetId) {
          try {
             await appendPatientToSheet(spreadsheetId, newPatient);
             // 3. Update local UI only if Sheet update was successful (or to reflect optimistic UI)
             onAddPatient(newPatient);
             setInputText('');
             setStatusMessage({ type: 'success', text: 'Paciente registrado en Google Sheets y localmente.' });
          } catch (sheetError) {
             console.error(sheetError);
             setStatusMessage({ type: 'error', text: 'Datos analizados, pero falló al guardar en Google Sheet. Revisa permisos/ID.' });
             // Still add locally so data isn't lost? Let's strictly require Sheet success for "Real Integration" feel, 
             // or add locally and warn. Let's add locally to be safe.
             onAddPatient(newPatient);
          }
        } else {
           // Offline/No-Auth mode
           onAddPatient(newPatient);
           setInputText('');
           setStatusMessage({ type: 'success', text: 'Paciente registrado localmente (Google Sheets no conectado).' });
        }

      } else {
        setStatusMessage({ type: 'error', text: 'No se pudo interpretar la información. Intenta ser más claro.' });
      }
    } catch (err: any) {
      setStatusMessage({ type: 'error', text: err.message || 'Error al procesar.' });
    } finally {
      setIsProcessing(false);
    }
  };

  const exportToCSV = () => {
    const headers = ["Fecha", "Nombre", "Apellido", "Edad", "Documento", "Descripción", "Psicólogo", "Tipo"];
    const rows = patients.map(p => [
      p.fecha,
      p.nombre,
      p.apellido,
      p.edad,
      p.documentoIdentidad,
      `"${p.descripcion}"`,
      p.psicologo,
      p.tipo
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
      + [headers.join(','), ...rows.map(e => e.join(','))].join('\n');

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "matriz_pacientes.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const filteredPatients = patients.filter(patient => {
    const term = searchTerm.toLowerCase();
    const fullName = `${patient.nombre} ${patient.apellido}`.toLowerCase();
    return (
      fullName.includes(term) ||
      patient.fecha.includes(term) ||
      patient.psicologo.toLowerCase().includes(term) ||
      patient.documentoIdentidad.includes(term) ||
      patient.tipo.toLowerCase().includes(term)
    );
  });

  const totalPages = Math.ceil(filteredPatients.length / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const displayedPatients = filteredPatients.slice(startIndex, startIndex + itemsPerPage);

  const goToPreviousPage = () => setCurrentPage(prev => Math.max(prev - 1, 1));
  const goToNextPage = () => setCurrentPage(prev => Math.min(prev + 1, totalPages));

  return (
    <div className="space-y-6 max-w-6xl mx-auto">
      <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-8 gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Matriz de Pacientes</h2>
          <div className="flex items-center gap-2 mt-1">
             <p className="text-gray-500">Registra pacientes en tu Google Sheet.</p>
             {isAuthenticated && spreadsheetId ? (
               <span className="text-xs bg-green-100 text-green-700 px-2 py-0.5 rounded-full flex items-center gap-1">
                 <CloudUpload size={10} /> Conectado a Sheets
               </span>
             ) : (
               <span className="text-xs bg-gray-100 text-gray-500 px-2 py-0.5 rounded-full">Modo Local</span>
             )}
          </div>
        </div>
        <button 
          onClick={exportToCSV}
          className="w-full sm:w-auto flex items-center justify-center gap-2 bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded-lg font-medium transition-colors shadow-sm"
        >
          <FileSpreadsheet size={18} />
          Exportar CSV
        </button>
      </header>

      {/* Input Section */}
      <div className="bg-white p-4 md:p-6 rounded-2xl shadow-sm border border-gray-200">
        <label className="block text-sm font-semibold text-gray-700 mb-2">
          Entrada Rápida
        </label>
        <div className="relative">
          <textarea
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            placeholder="Ej: Laura nunez, 32, 40200564348, separacion, Dra Aurora (primera vez)"
            className="w-full h-32 p-4 bg-gray-800 border border-gray-700 rounded-xl focus:ring-2 focus:ring-teal-500 focus:border-teal-500 transition-all resize-none text-white placeholder-gray-400 pb-16"
          />
          <button
            onClick={handleProcess}
            disabled={isProcessing || !inputText}
            className={`absolute bottom-4 right-4 flex items-center gap-2 px-4 py-2 rounded-lg font-medium text-white transition-all ${
              isProcessing || !inputText 
                ? 'bg-gray-600 cursor-not-allowed' 
                : 'bg-teal-600 hover:bg-teal-700 shadow-md hover:shadow-lg'
            }`}
          >
            {isProcessing ? (
              <>
                <Loader2 size={18} className="animate-spin" />
                <span className="hidden sm:inline">Procesando...</span>
              </>
            ) : (
              <>
                <Sparkles size={18} />
                <span className="hidden sm:inline">Procesar y Guardar</span>
                <span className="sm:hidden">Procesar</span>
              </>
            )}
          </button>
        </div>
        {statusMessage && (
          <p className={`text-sm mt-2 ${statusMessage.type === 'error' ? 'text-red-500' : 'text-green-600'}`}>
            {statusMessage.text}
          </p>
        )}
      </div>

      {/* Filter & Table Section */}
      <div className="space-y-4">
        {/* Search Bar */}
        <div className="relative">
          <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
            <Search className="h-5 w-5 text-gray-400" />
          </div>
          <input
            type="text"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="block w-full pl-10 pr-10 py-2 border border-gray-200 rounded-xl leading-5 bg-white placeholder-gray-400 focus:outline-none focus:ring-1 focus:ring-teal-500 focus:border-teal-500 sm:text-sm shadow-sm"
            placeholder="Buscar por nombre, fecha o psicólogo..."
          />
          {searchTerm && (
            <button 
              onClick={() => setSearchTerm('')}
              className="absolute inset-y-0 right-0 pr-3 flex items-center text-gray-400 hover:text-gray-600 transition-colors"
            >
              <X size={16} />
            </button>
          )}
        </div>

        {/* Table */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left text-sm text-gray-600">
              <thead className="bg-gray-50 border-b border-gray-200 text-xs uppercase font-semibold text-gray-500 tracking-wider">
                <tr>
                  <th className="px-6 py-4">Fecha</th>
                  <th className="px-6 py-4">Nombre Completo</th>
                  <th className="px-6 py-4">Edad</th>
                  <th className="px-6 py-4">Documento</th>
                  <th className="px-6 py-4">Motivo</th>
                  <th className="px-6 py-4">Psicólogo</th>
                  <th className="px-6 py-4">Tipo</th>
                  <th className="px-6 py-4 text-right">Acciones</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {filteredPatients.length === 0 ? (
                  <tr>
                    <td colSpan={8} className="px-6 py-12 text-center text-gray-400">
                      {searchTerm ? <span>No se encontraron resultados para "{searchTerm}".</span> : <span>No hay pacientes registrados.</span>}
                    </td>
                  </tr>
                ) : (
                  displayedPatients.map((patient) => (
                    <tr key={patient.id} className="hover:bg-teal-50/40 transition-colors duration-200">
                      <td className="px-6 py-4 whitespace-nowrap">{patient.fecha}</td>
                      <td className="px-6 py-4 font-bold text-base text-gray-900 whitespace-nowrap">
                        {patient.nombre} {patient.apellido}
                      </td>
                      <td className="px-6 py-4">{patient.edad}</td>
                      <td className="px-6 py-4 font-mono text-xs text-gray-500">{patient.documentoIdentidad}</td>
                      <td className="px-6 py-4 max-w-xs truncate text-gray-500" title={patient.descripcion}>
                        {patient.descripcion}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-100 text-blue-800">
                          {patient.psicologo}
                        </span>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <span className={`inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full text-xs font-medium ${
                          patient.tipo === 'Nuevo' ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-600'
                        }`}>
                          {patient.tipo === 'Nuevo' ? <UserPlus size={12} /> : <UserCheck size={12} />}
                          {patient.tipo}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <button 
                          onClick={() => onDeletePatient(patient.id)}
                          className="text-gray-400 hover:text-red-500 transition-colors"
                        >
                          <Trash2 size={16} />
                        </button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>

          {/* Pagination Controls */}
          {filteredPatients.length > 0 && (
            <div className="bg-gray-50 px-6 py-4 border-t border-gray-200 flex items-center justify-between">
              <div className="text-sm text-gray-500">
                Mostrando <span className="font-medium">{startIndex + 1}</span> a <span className="font-medium">{Math.min(startIndex + itemsPerPage, filteredPatients.length)}</span> de <span className="font-medium">{filteredPatients.length}</span>
              </div>
              <div className="flex items-center gap-2">
                <button
                  onClick={goToPreviousPage}
                  disabled={currentPage === 1}
                  className={`p-2 rounded-lg border border-gray-300 transition-all ${currentPage === 1 ? 'bg-gray-100 text-gray-400' : 'bg-white hover:bg-gray-50'}`}
                >
                  <ChevronLeft size={16} />
                </button>
                <div className="flex items-center gap-1 px-2">
                  <span className="text-sm font-medium text-gray-700">{currentPage}</span>
                  <span className="text-sm text-gray-400">/ {totalPages || 1}</span>
                </div>
                <button
                  onClick={goToNextPage}
                  disabled={currentPage === totalPages || totalPages === 0}
                  className={`p-2 rounded-lg border border-gray-300 transition-all ${currentPage === totalPages ? 'bg-gray-100 text-gray-400' : 'bg-white hover:bg-gray-50'}`}
                >
                  <ChevronRight size={16} />
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { PatientManager } from './components/PatientManager';
import { DigitalNotebook } from './components/DigitalNotebook';
import { Dashboard } from './components/Dashboard';
import { Patient, Task, CalendarEvent, ViewState, AppSettings } from './types';
import { initGoogleServices, handleLogin, handleLogout } from './services/googleApiService';
import { Settings as SettingsIcon, AlertCircle, Menu, HeartPulse, LogIn, Save, LogOut } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // App State
  const [patients, setPatients] = useState<Patient[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [events, setEvents] = useState<CalendarEvent[]>([]);

  // Auth & Settings State
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [settings, setSettings] = useState<AppSettings>({
    googleClientId: localStorage.getItem('googleClientId') || '',
    spreadsheetId: localStorage.getItem('spreadsheetId') || ''
  });
  const [isGapiReady, setIsGapiReady] = useState(false);

  useEffect(() => {
    // Check if API Key is env var exists (for Gemini)
    // Initialize Google Services if Client ID is present
    if (settings.googleClientId) {
      initGoogleServices(settings.googleClientId, (success) => {
        setIsGapiReady(success);
      });
    }
  }, [settings.googleClientId]);

  const onLogin = async () => {
    try {
      await handleLogin();
      setIsAuthenticated(true);
    } catch (error) {
      alert("Fallo al iniciar sesión en Google");
    }
  };

  const onLogout = () => {
    handleLogout();
    setIsAuthenticated(false);
  };

  const saveSettings = () => {
    localStorage.setItem('googleClientId', settings.googleClientId);
    localStorage.setItem('spreadsheetId', settings.spreadsheetId);
    window.location.reload(); // Reload to re-init GAPI with new ID
  };

  // State handlers (now acting mostly as local cache/optimistic UI)
  const handleAddPatient = (patient: Patient) => {
    setPatients(prev => [patient, ...prev]);
  };

  const handleDeletePatient = (id: string) => {
    setPatients(prev => prev.filter(p => p.id !== id));
  };

  const handleAddTasks = (newTasks: Task[]) => {
    setTasks(prev => [...prev, ...newTasks]);
  };

  const handleAddEvents = (newEvents: CalendarEvent[]) => {
    setEvents(prev => [...prev, ...newEvents]);
  };

  const handleToggleTask = (id: string) => {
    setTasks(prev => prev.map(t => t.id === id ? { ...t, isDone: !t.isDone } : t));
  };

  const handleDeleteTask = (id: string) => {
    setTasks(prev => prev.filter(t => t.id !== id));
  };

  const handleDeleteEvent = (id: string) => {
    setEvents(prev => prev.filter(e => e.id !== id));
  };

  return (
    <div className="flex h-screen bg-[#F8FAFC] overflow-hidden">
      {/* Mobile Header */}
      <div className="md:hidden fixed top-0 left-0 right-0 h-16 bg-white border-b border-gray-200 z-30 flex items-center justify-between px-4">
        <div className="flex items-center gap-2 text-teal-600">
          <HeartPulse size={24} />
          <span className="font-bold text-lg text-gray-800">Idguie</span>
        </div>
        <button 
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
          className="p-2 text-gray-600 hover:bg-gray-100 rounded-lg"
        >
          <Menu size={24} />
        </button>
      </div>

      {/* Sidebar Overlay for Mobile */}
      {isMobileMenuOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 md:hidden"
          onClick={() => setIsMobileMenuOpen(false)}
        />
      )}

      {/* Sidebar - Responsive */}
      <div className={`
        fixed inset-y-0 left-0 z-50 transform transition-transform duration-300 ease-in-out md:relative md:translate-x-0
        ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <Sidebar 
          currentView={currentView} 
          onChangeView={setCurrentView} 
          onCloseMobile={() => setIsMobileMenuOpen(false)}
        />
      </div>

      {/* Main Content */}
      <main className="flex-1 overflow-auto p-4 md:p-8 pt-20 md:pt-8 w-full relative">
        {/* Top Bar: Auth Status */}
        <div className="flex justify-end mb-4">
          {!isAuthenticated ? (
            <button 
              onClick={onLogin} 
              disabled={!isGapiReady}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg font-medium text-sm transition-all ${
                isGapiReady 
                  ? 'bg-blue-600 text-white hover:bg-blue-700 shadow-sm' 
                  : 'bg-gray-200 text-gray-400 cursor-not-allowed'
              }`}
            >
              <LogIn size={16} />
              {isGapiReady ? 'Conectar con Google' : 'Configura Client ID'}
            </button>
          ) : (
            <button 
              onClick={onLogout}
              className="flex items-center gap-2 px-4 py-2 bg-white border border-gray-200 text-gray-600 hover:bg-gray-50 rounded-lg font-medium text-sm transition-all"
            >
              <LogOut size={16} />
              Desconectar
            </button>
          )}
        </div>

        {/* API Key Warning Overlay */}
        {!process.env.API_KEY && (
           <div className="mb-6 bg-red-50 border border-red-200 rounded-lg p-4 flex items-start gap-3">
             <AlertCircle className="text-red-500 mt-0.5 shrink-0" />
             <div>
               <h4 className="font-bold text-red-700">Falta la API Key de Gemini</h4>
               <p className="text-sm text-red-600 break-words">
                 Esta aplicación requiere una Google Gemini API Key en el entorno.
               </p>
             </div>
           </div>
        )}

        {currentView === ViewState.DASHBOARD && (
          <Dashboard 
            patients={patients}
            tasks={tasks}
            events={events}
            onChangeView={setCurrentView}
          />
        )}

        {currentView === ViewState.PATIENTS && (
          <PatientManager 
            patients={patients}
            onAddPatient={handleAddPatient}
            onDeletePatient={handleDeletePatient}
            isAuthenticated={isAuthenticated}
            spreadsheetId={settings.spreadsheetId}
          />
        )}

        {currentView === ViewState.NOTEBOOK && (
          <DigitalNotebook 
            tasks={tasks}
            events={events}
            onAddTasks={handleAddTasks}
            onAddEvents={handleAddEvents}
            onToggleTask={handleToggleTask}
            onDeleteTask={handleDeleteTask}
            onDeleteEvent={handleDeleteEvent}
            isAuthenticated={isAuthenticated}
          />
        )}

        {currentView === ViewState.SETTINGS && (
          <div className="max-w-2xl mx-auto bg-white p-6 md:p-8 rounded-2xl shadow-sm border border-gray-100">
            <div className="flex items-center gap-3 mb-6 pb-6 border-b border-gray-100">
              <div className="w-12 h-12 bg-gray-100 rounded-full flex items-center justify-center text-gray-500 shrink-0">
                <SettingsIcon size={24} />
              </div>
              <div>
                <h2 className="text-xl font-bold text-gray-800">Configuración</h2>
                <p className="text-gray-500 text-sm">Conexiones con Google Workspace</p>
              </div>
            </div>

            <div className="space-y-6">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Google Client ID (OAuth 2.0)</label>
                <input 
                  type="text" 
                  value={settings.googleClientId}
                  onChange={(e) => setSettings({...settings, googleClientId: e.target.value})}
                  className="w-full p-2 border border-gray-300 rounded-lg text-sm font-mono focus:ring-2 focus:ring-teal-500 outline-none"
                  placeholder="xxxx-xxxx.apps.googleusercontent.com"
                />
                <p className="text-xs text-gray-400 mt-1">Necesario para Sheets, Tasks y Calendar.</p>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Google Sheet ID (Matriz Pacientes)</label>
                <input 
                  type="text" 
                  value={settings.spreadsheetId}
                  onChange={(e) => setSettings({...settings, spreadsheetId: e.target.value})}
                  className="w-full p-2 border border-gray-300 rounded-lg text-sm font-mono focus:ring-2 focus:ring-teal-500 outline-none"
                  placeholder="1BxiMVs0XRA5nFMdKb..."
                />
                <p className="text-xs text-gray-400 mt-1">El ID largo en la URL de tu Google Sheet.</p>
              </div>

              <div className="pt-4">
                <button 
                  onClick={saveSettings}
                  className="flex items-center gap-2 bg-teal-600 text-white px-4 py-2 rounded-lg hover:bg-teal-700 transition-colors"
                >
                  <Save size={16} />
                  Guardar Configuración
                </button>
              </div>

              <div className="bg-blue-50 p-4 rounded-lg border border-blue-100 text-sm text-blue-800 mt-6">
                <p className="mb-2"><strong>Instrucciones:</strong></p>
                <ol className="list-decimal pl-4 space-y-1 text-xs">
                  <li>Crea un proyecto en <a href="https://console.cloud.google.com" target="_blank" className="underline">Google Cloud Console</a>.</li>
                  <li>Habilita las APIs: <strong>Google Sheets API</strong>, <strong>Google Tasks API</strong>, <strong>Google Calendar API</strong>.</li>
                  <li>Crea credenciales "OAuth 2.0 Client ID" (Web Application).</li>
                  <li>Añade tu URL local (ej. http://localhost:5173) a "Authorized JavaScript origins".</li>
                  <li>Copia el Client ID aquí.</li>
                  <li>Crea una Sheet llamada "Matriz de Pacientes Atendidos" y copia su ID aquí.</li>
                </ol>
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { parseNotebookEntry } from '../services/geminiService';
import { createGoogleTask, createGoogleCalendarEvent } from '../services/googleApiService';
import { Task, CalendarEvent } from '../types';
import { Sparkles, CheckCircle2, Calendar, Clock, Loader2, Flag, Check, Trash2, AlertTriangle, X } from 'lucide-react';

interface DigitalNotebookProps {
  tasks: Task[];
  events: CalendarEvent[];
  onAddTasks: (tasks: Task[]) => void;
  onAddEvents: (events: CalendarEvent[]) => void;
  onToggleTask: (id: string) => void;
  onDeleteTask: (id: string) => void;
  onDeleteEvent: (id: string) => void;
  isAuthenticated: boolean;
}

export const DigitalNotebook: React.FC<DigitalNotebookProps> = ({ 
  tasks, 
  events, 
  onAddTasks, 
  onAddEvents, 
  onToggleTask, 
  onDeleteTask,
  onDeleteEvent,
  isAuthenticated 
}) => {
  const [inputText, setInputText] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [manualPriority, setManualPriority] = useState<'Auto' | 'High' | 'Medium' | 'Low'>('Auto');

  // Delete Modal State
  const [deleteModal, setDeleteModal] = useState<{isOpen: boolean, type: 'task' | 'event', id: string} | null>(null);

  const handleProcess = async () => {
    if (!inputText.trim()) return;

    setIsProcessing(true);
    try {
      // 1. Parse with Gemini
      const result = await parseNotebookEntry(inputText);

      if (result) {
        const newTasks: Task[] = result.tasks.map(t => ({
          id: crypto.randomUUID(),
          title: t.title,
          isDone: false,
          priority: manualPriority !== 'Auto' ? manualPriority : t.priority
        }));

        const newEvents: CalendarEvent[] = result.events.map(e => ({
          id: crypto.randomUUID(),
          title: e.title,
          date: e.date,
          time: e.time,
          description: e.description
        }));

        // 2. Real Integration: Send to Google
        if (isAuthenticated) {
          // Process Tasks
          for (const task of newTasks) {
            try {
              await createGoogleTask(task);
            } catch (e) {
              console.error("Failed to sync task", e);
            }
          }
          // Process Events
          for (const event of newEvents) {
            try {
              await createGoogleCalendarEvent(event);
            } catch (e) {
               console.error("Failed to sync event", e);
            }
          }
        }

        // 3. Update Local UI
        onAddTasks(newTasks);
        onAddEvents(newEvents);
        setInputText('');
        setManualPriority('Auto');
      }
    } catch (error) {
      console.error(error);
      alert("Error al procesar la nota.");
    } finally {
      setIsProcessing(false);
    }
  };

  const getPriorityColor = (p: string) => {
    switch(p) {
      case 'High': return 'text-red-500';
      case 'Medium': return 'text-yellow-500';
      case 'Low': return 'text-gray-500';
      default: return 'text-indigo-500';
    }
  };

  const promptDelete = (type: 'task' | 'event', id: string) => {
    setDeleteModal({ isOpen: true, type, id });
  };

  const confirmDelete = () => {
    if (!deleteModal) return;

    if (deleteModal.type === 'task') {
      onDeleteTask(deleteModal.id);
    } else {
      onDeleteEvent(deleteModal.id);
    }
    setDeleteModal(null);
  };

  return (
    <div className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8 h-auto lg:h-[calc(100vh-8rem)] relative">

      {/* Delete Confirmation Modal */}
      {deleteModal && deleteModal.isOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/40 backdrop-blur-sm">
          <div className="bg-white rounded-xl shadow-xl max-w-sm w-full p-6 transform transition-all scale-100">
            <div className="flex items-center gap-3 text-red-600 mb-4">
              <div className="bg-red-100 p-2 rounded-full">
                <AlertTriangle size={24} />
              </div>
              <h3 className="text-lg font-bold">¿Eliminar elemento?</h3>
            </div>
            <p className="text-gray-600 mb-6 text-sm">
              ¿Estás seguro de que quieres eliminar este {deleteModal.type === 'task' ? 'tarea' : 'evento'}?
              Esta acción eliminará el elemento de tu vista local.
            </p>
            <div className="flex justify-end gap-3">
              <button 
                onClick={() => setDeleteModal(null)}
                className="px-4 py-2 text-gray-600 font-medium hover:bg-gray-100 rounded-lg transition-colors"
              >
                Cancelar
              </button>
              <button 
                onClick={confirmDelete}
                className="px-4 py-2 bg-red-600 text-white font-medium rounded-lg hover:bg-red-700 shadow-md transition-colors"
              >
                Eliminar
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Input Column */}
      <div className="flex flex-col gap-6 h-full">
        <div>
