              <a 
                href={lastPaymentLink} 
                target="_blank" 
                rel="noreferrer"
                className="text-xs flex items-center gap-1 underline hover:text-green-800"
              >
                Ver comprobante en Drive <ExternalLink size={12} />
              </a>
            )}
          </div>
        )}
