import React, { useState } from 'react';
import { WaitingListEntry } from '../types';
import { Hourglass, UserPlus, Phone, Trash2, MessageCircle, Clock, CalendarClock } from 'lucide-react';

interface WaitingListManagerProps {
  waitingList: WaitingListEntry[];
  onAddEntry: (entry: WaitingListEntry) => void;
  onRemoveEntry: (id: string) => void;
}

export const WaitingListManager: React.FC<WaitingListManagerProps> = ({ waitingList, onAddEntry, onRemoveEntry }) => {
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [preference, setPreference] = useState('');
  const [notes, setNotes] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !phone) return;

    const newEntry: WaitingListEntry = {
      id: crypto.randomUUID(),
      nombre: name,
      telefono: phone,
      preferenciaHoraria: preference,
      notas: notes,
      fechaAgregado: Date.now()
    };

    onAddEntry(newEntry);
    setName('');
    setPhone('');
    setPreference('');
    setNotes('');
  };

  const handleWhatsAppClick = (entry: WaitingListEntry) => {
    // Basic phone cleaning
    const cleanPhone = entry.telefono.replace(/\D/g, ''); 

    // Construct message
    const message = `Hola ${entry.nombre}, te escribo del Centro de Bienestar. Se liberó un espacio en la agenda [AGREGAR HORA AQUÍ], ¿te interesa tomarlo?`;

    // Open WhatsApp
    const url = `https://wa.me/${cleanPhone}?text=${encodeURIComponent(message)}`;
    window.open(url, '_blank');
  };

  const formatWaitTime = (timestamp: number) => {
    const days = Math.floor((Date.now() - timestamp) / (1000 * 60 * 60 * 24));
    if (days === 0) return 'Hoy';
    if (days === 1) return 'Hace 1 día';
    return `Hace ${days} días`;
  };

  return (
    <div className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-8 h-[calc(100vh-8rem)]">

      {/* Left Column: Form */}
      <div className="lg:col-span-1 space-y-6">
        <div>
          <h2 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
            <Hourglass className="text-teal-600" />
            Lista de Espera
          </h2>
          <p className="text-gray-500 mt-1 text-sm">
            Registra pacientes interesados para cubrir cancelaciones de último minuto.
          </p>
        </div>

        <form onSubmit={handleSubmit} className="bg-white p-6 rounded-2xl shadow-sm border border-gray-200 space-y-4">
           <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Nombre del Paciente</label>
            <div className="relative">
              <UserPlus className="absolute left-3 top-3 text-gray-400" size={18} />
              <input
                type="text"
                value={name}
                onChange={(e) => setName(e.target.value)}
                placeholder="Ej: Juan Pérez"
                className="w-full pl-10 p-2.5 border border-gray-200 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none text-sm"
                required
              />
            </div>
           </div>

           <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Teléfono (WhatsApp)</label>
            <div className="relative">
              <Phone className="absolute left-3 top-3 text-gray-400" size={18} />
              <input
                type="tel"
                value={phone}
                onChange={(e) => setPhone(e.target.value)}
                placeholder="Ej: 51999999999"
                className="w-full pl-10 p-2.5 border border-gray-200 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none text-sm"
                required
              />
            </div>
            <p className="text-xs text-gray-400 mt-1">Incluye código de país si es necesario (ej: 51 para Perú).</p>
           </div>

           <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Preferencia Horaria</label>
            <div className="relative">
              <CalendarClock className="absolute left-3 top-3 text-gray-400" size={18} />
              <input
                type="text"
                value={preference}
                onChange={(e) => setPreference(e.target.value)}
                placeholder="Ej: Solo mañanas, Martes tardes..."
                className="w-full pl-10 p-2.5 border border-gray-200 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none text-sm"
              />
            </div>
           </div>

           <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Notas Adicionales</label>
            <textarea
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              placeholder="Ej: Paciente urgente..."
              className="w-full p-3 border border-gray-200 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none text-sm resize-none h-20"
            />
           </div>

           <button
            type="submit"
            className="w-full bg-teal-600 hover:bg-teal-700 text-white font-medium py-2.5 rounded-lg transition-colors flex items-center justify-center gap-2"
           >
             <UserPlus size={18} />
             Agregar a Lista
           </button>
        </form>

        <div className="bg-blue-50 border border-blue-100 p-4 rounded-xl text-sm text-blue-800">
          <p className="font-bold mb-1">💡 Estrategia de Ingresos</p>
          <p>Cuando se libere un espacio, busca aquí a alguien con horario compatible y envíale un WhatsApp al instante.</p>
        </div>
      </div>

      {/* Right Column: List */}
      <div className="lg:col-span-2 flex flex-col h-full overflow-hidden">
        <div className="bg-white rounded-2xl shadow-sm border border-gray-200 flex-1 flex flex-col overflow-hidden">
          <div className="px-6 py-4 border-b border-gray-100 bg-gray-50 flex items-center justify-between">
            <h3 className="font-semibold text-gray-800">Pacientes en Espera ({waitingList.length})</h3>
            <span className="text-xs text-gray-500">Ordenado por antigüedad</span>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-3">
            {waitingList.length === 0 && (
              <div className="h-full flex flex-col items-center justify-center text-gray-400">
                <Hourglass size={48} className="mb-4 opacity-20" />
                <p>La lista de espera está vacía.</p>
              </div>
            )}

            {waitingList.map((entry) => (
              <div key={entry.id} className="group bg-white border border-gray-100 rounded-xl p-4 hover:shadow-md transition-all flex flex-col sm:flex-row sm:items-center gap-4">

                {/* Info */}
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 mb-1">
                    <h4 className="font-bold text-gray-900 truncate">{entry.nombre}</h4>
                    <span className="text-xs bg-gray-100 text-gray-500 px-2 py-0.5 rounded-full flex items-center gap-1">
                      <Clock size={10} /> {formatWaitTime(entry.fechaAgregado)}
                    </span>
                  </div>
                  <div className="text-sm text-gray-600 mb-1 flex items-center gap-2">
                     <span className="font-medium text-teal-700 bg-teal-50 px-2 py-0.5 rounded text-xs">
                        Pref: {entry.preferenciaHoraria || 'Sin preferencia'}
                     </span>
                     <span className="text-gray-400">|</span>
                     <span>{entry.telefono}</span>
                  </div>
                  {entry.notas && (
                    <p className="text-xs text-gray-500 italic truncate">{entry.notas}</p>
                  )}
                </div>

                {/* Actions */}
                <div className="flex items-center gap-2 sm:border-l sm:border-gray-100 sm:pl-4">
                  <button
                    onClick={() => handleWhatsAppClick(entry)}
                    className="flex items-center gap-2 bg-green-500 hover:bg-green-600 text-white px-4 py-2 rounded-lg font-medium text-sm transition-colors shadow-sm"
                    title="Enviar WhatsApp de espacio libre"
                  >
                    <MessageCircle size={18} />
                    <span className="hidden sm:inline">Ofrecer Espacio</span>
                    <span className="sm:hidden">WhatsApp</span>
                  </button>

                  <button
                    onClick={() => onRemoveEntry(entry.id)}
                    className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                    title="Eliminar de la lista"
                  >
                    <Trash2 size={18} />
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { PatientManager } from './components/PatientManager';
import { DigitalNotebook } from './components/DigitalNotebook';
import { FinanceManager } from './components/FinanceManager';
import { WaitingListManager } from './components/WaitingListManager'; // Import new component
import { Dashboard } from './components/Dashboard';
import { Patient, Task, CalendarEvent, ViewState, AppSettings, WaitingListEntry } from './types';
import { initGoogleServices, handleLogin, handleLogout } from './services/googleApiService';
import { Settings as SettingsIcon, AlertCircle, Menu, HeartPulse, LogIn, Save, LogOut, Database } from 'lucide-react';

// Data Retention Configuration
const RETENTION_DAYS = 90;
const MS_PER_DAY = 24 * 60 * 60 * 1000;
const RETENTION_MS = RETENTION_DAYS * MS_PER_DAY;

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // App State
  const [patients, setPatients] = useState<Patient[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [waitingList, setWaitingList] = useState<WaitingListEntry[]>([]); // New State
  const [dataLoaded, setDataLoaded] = useState(false);

  // Auth & Settings State
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [settings, setSettings] = useState<AppSettings>({
    googleClientId: localStorage.getItem('googleClientId') || '',
    spreadsheetId: localStorage.getItem('spreadsheetId') || '',
    financeFolderId: localStorage.getItem('financeFolderId') || ''
  });
  const [isGapiReady, setIsGapiReady] = useState(false);

  // --- Persistence Logic ---

  // 1. Load data on mount
  useEffect(() => {
    const loadData = (key: string, setter: React.Dispatch<React.SetStateAction<any[]>>) => {
      const stored = localStorage.getItem(`app_data_${key}`);
      if (stored) {
        try {
          const parsed = JSON.parse(stored);
          const age = Date.now() - parsed.timestamp;

          if (age < RETENTION_MS) {
            setter(parsed.data);
          } else {
            console.log(`Data for ${key} expired. Clearing.`);
            localStorage.removeItem(`app_data_${key}`);
          }
        } catch (e) {
          console.error(`Error loading ${key}`, e);
        }
      }
    };

    loadData('patients', setPatients);
    loadData('tasks', setTasks);
    loadData('events', setEvents);
    loadData('waitingList', setWaitingList); // Load waiting list
    setDataLoaded(true);
  }, []);

  // 2. Save data on change
  useEffect(() => {
    if (!dataLoaded) return;
    localStorage.setItem('app_data_patients', JSON.stringify({ timestamp: Date.now(), data: patients }));
  }, [patients, dataLoaded]);

  useEffect(() => {
    if (!dataLoaded) return;
    localStorage.setItem('app_data_tasks', JSON.stringify({ timestamp: Date.now(), data: tasks }));
  }, [tasks, dataLoaded]);

  useEffect(() => {
    if (!dataLoaded) return;
    localStorage.setItem('app_data_events', JSON.stringify({ timestamp: Date.now(), data: events }));
  }, [events, dataLoaded]);

  useEffect(() => {
    if (!dataLoaded) return;
    localStorage.setItem('app_data_waitingList', JSON.stringify({ timestamp: Date.now(), data: waitingList }));
  }, [waitingList, dataLoaded]);

  // --- End Persistence Logic ---

  useEffect(() => {
    if (settings.googleClientId) {
      initGoogleServices(settings.googleClientId, (success) => {
        setIsGapiReady(success);
      });
    }
  }, [settings.googleClientId]);

  const onLogin = async () => {
    try {
      await handleLogin();
      setIsAuthenticated(true);
    } catch (error) {
      alert("Fallo al iniciar sesión en Google");
    }
  };

  const onLogout = () => {
    handleLogout();
    setIsAuthenticated(false);
  };

  const saveSettings = () => {
    localStorage.setItem('googleClientId', settings.googleClientId);
    localStorage.setItem('spreadsheetId', settings.spreadsheetId);
    localStorage.setItem('financeFolderId', settings.financeFolderId);
    window.location.reload(); 
  };

  // State handlers
  const handleAddPatient = (patient: Patient) => {
    setPatients(prev => [patient, ...prev]);
  };

  const handleDeletePatient = (id: string) => {
    setPatients(prev => prev.filter(p => p.id !== id));
  };

  const handleAddTasks = (newTasks: Task[]) => {
    setTasks(prev => [...prev, ...newTasks]);
  };

  const handleAddEvents = (newEvents: CalendarEvent[]) => {
    setEvents(prev => [...prev, ...newEvents]);
  };

  const handleToggleTask = (id: string) => {
    setTasks(prev => prev.map(t => t.id === id ? { ...t, isDone: !t.isDone } : t));
  };

  const handleDeleteTask = (id: string) => {
    setTasks(prev => prev.filter(t => t.id !== id));
  };

  const handleDeleteEvent = (id: string) => {
    setEvents(prev => prev.filter(e => e.id !== id));
  };

  // Waiting List Handlers
  const handleAddWaitingEntry = (entry: WaitingListEntry) => {
    setWaitingList(prev => [...prev, entry]);
  };

  const handleRemoveWaitingEntry = (id: string) => {
    setWaitingList(prev => prev.filter(entry => entry.id !== id));
  };

  return (
    <div className="flex h-screen bg-[#F8FAFC] overflow-hidden">
      {/* Mobile Header */}
      <div className="md:hidden fixed top-0 left-0 right-0 h-16 bg-white border-b border-gray-200 z-30 flex items-center justify-between px-4">
        <div className="flex items-center gap-2 text-teal-600">
          <HeartPulse size={24} />
          <span className="font-bold text-lg text-gray-800">Idguie</span>
        </div>
        <button 
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
          className="p-2 text-gray-600 hover:bg-gray-100 rounded-lg"
        >
          <Menu size={24} />
        </button>
      </div>

      {/* Sidebar Overlay for Mobile */}
      {isMobileMenuOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 md:hidden"
          onClick={() => setIsMobileMenuOpen(false)}
        />
      )}

      {/* Sidebar - Responsive */}
      <div className={`
        fixed inset-y-0 left-0 z-50 transform transition-transform duration-300 ease-in-out md:relative md:translate-x-0
        ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <Sidebar 
          currentView={currentView} 
          onChangeView={setCurrentView} 
          onCloseMobile={() => setIsMobileMenuOpen(false)}
        />
      </div>

      {/* Main Content */}
      <main className="flex-1 overflow-auto p-4 md:p-8 pt-20 md:pt-8 w-full relative">
        {/* Top Bar: Auth Status */}
        <div className="flex justify-end mb-4 gap-3">
           <div className="hidden md:flex items-center gap-2 text-xs text-gray-400 bg-gray-50 px-3 py-1 rounded-full border border-gray-100">
              <Database size={12} />
              <span>Memoria local: {RETENTION_DAYS} días</span>
           </div>

          {!isAuthenticated ? (
            <button 
              onClick={onLogin} 
              disabled={!isGapiReady}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg font-medium text-sm transition-all ${
                isGapiReady 
                  ? 'bg-blue-600 text-white hover:bg-blue-700 shadow-sm' 
                  : 'bg-gray-200 text-gray-400 cursor-not-allowed'
              }`}
            >
              <LogIn size={16} />
              {isGapiReady ? 'Conectar con Google' : 'Configura Client ID'}
            </button>
          ) : (
            <button 
              onClick={onLogout}
              className="flex items-center gap-2 px-4 py-2 bg-white border border-gray-200 text-gray-600 hover:bg-gray-50 rounded-lg font-medium text-sm transition-all"
            >
              <LogOut size={16} />
              Desconectar
            </button>
          )}
        </div>

        {/* API Key Warning Overlay */}
        {!process.env.API_KEY && (
           <div className="mb-6 bg-red-50 border border-red-200 rounded-lg p-4 flex items-start gap-3">
             <AlertCircle className="text-red-500 mt-0.5 shrink-0" />
             <div>
               <h4 className="font-bold text-red-700">Falta la API Key de Gemini</h4>
               <p className="text-sm text-red-600 break-words">
                 Esta aplicación requiere una Google Gemini API Key en el entorno.
               </p>
             </div>
           </div>
        )}

        {currentView === ViewState.DASHBOARD && (
          <Dashboard 
            patients={patients}
            tasks={tasks}
            events={events}
            onChangeView={setCurrentView}
          />
        )}

        {currentView === ViewState.PATIENTS && (
          <PatientManager 
            patients={patients}
            onAddPatient={handleAddPatient}
            onDeletePatient={handleDeletePatient}
            isAuthenticated={isAuthenticated}
            spreadsheetId={settings.spreadsheetId}
          />
        )}

        {currentView === ViewState.NOTEBOOK && (
          <DigitalNotebook 
            tasks={tasks}
            events={events}
            onAddTasks={handleAddTasks}
            onAddEvents={handleAddEvents}
            onToggleTask={handleToggleTask}
            onDeleteTask={handleDeleteTask}
            onDeleteEvent={handleDeleteEvent}
            isAuthenticated={isAuthenticated}
          />
        )}

        {currentView === ViewState.FINANCE && (
          <FinanceManager 
            isAuthenticated={isAuthenticated}
            spreadsheetId={settings.spreadsheetId}
            financeFolderId={settings.financeFolderId}
          />
        )}

        {currentView === ViewState.WAITING_LIST && (
          <WaitingListManager 
            waitingList={waitingList}
            onAddEntry={handleAddWaitingEntry}
            onRemoveEntry={handleRemoveWaitingEntry}
          />
        )}

        {currentView === ViewState.SETTINGS && (
          <div className="max-w-2xl mx-auto bg-white p-6 md:p-8 rounded-2xl shadow-sm border border-gray-100">
            <div className="flex items-center gap-3 mb-6 pb-6 border-b border-gray-100">
              <div className="w-12 h-12 bg-gray-100 rounded-full flex items-center justify-center text-gray-500 shrink-0">
                <SettingsIcon size={24} />
              </div>
              <div>
                <h2 className="text-xl font-bold text-gray-800">Configuración</h2>
                <p className="text-gray-500 text-sm">Conexiones con Google Workspace</p>
              </div>
            </div>

            <div className="space-y-6">
              <div>
