import React, { useState } from 'react';
import { uploadFileToDrive, appendPaymentToSheet } from '../services/googleApiService';
import { Payment } from '../types';
import { DollarSign, Upload, CheckCircle2, AlertCircle, Loader2, Image as ImageIcon, ExternalLink, Calendar, Search } from 'lucide-react';

interface FinanceManagerProps {
  isAuthenticated: boolean;
  spreadsheetId: string;
  financeFolderId: string;
  payments: Payment[];
  onAddPayment: (payment: Payment) => void;
}

export const FinanceManager: React.FC<FinanceManagerProps> = ({ 
  isAuthenticated, 
  spreadsheetId, 
  financeFolderId,
  payments,
  onAddPayment 
}) => {
  const [amount, setAmount] = useState('');
  const [patientName, setPatientName] = useState('');
  const [method, setMethod] = useState('Transferencia');
  const [file, setFile] = useState<File | null>(null);

  const [status, setStatus] = useState<'idle' | 'uploading' | 'success' | 'error'>('idle');
  const [lastPaymentLink, setLastPaymentLink] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || !patientName || !file) {
      alert("Por favor completa todos los campos y adjunta un comprobante.");
      return;
    }

    if (!isAuthenticated) {
      alert("Debes iniciar sesión con Google para registrar pagos.");
      return;
    }

    setStatus('uploading');

    try {
      // 1. Upload file to Drive
      const driveResponse = await uploadFileToDrive(file, financeFolderId);

      const newPayment: Payment = {
        id: crypto.randomUUID(),
        fecha: new Date().toLocaleDateString('es-ES'),
        paciente: patientName,
        monto: parseFloat(amount),
        metodo: method,
        comprobanteUrl: driveResponse.webViewLink,
        driveFileId: driveResponse.id
      };

      // 2. Append to Sheets
      await appendPaymentToSheet(spreadsheetId, newPayment);

      onAddPayment(newPayment);

      setStatus('success');
      setLastPaymentLink(driveResponse.webViewLink);

      // Reset form
      setAmount('');
      setPatientName('');
      setFile(null);
      // Keep status as success for a moment or until user types again
      setTimeout(() => setStatus('idle'), 5000);

    } catch (error) {
      console.error(error);
      setStatus('error');
    }
  };

  const filteredPayments = payments.filter(p => 
    p.paciente.toLowerCase().includes(searchTerm.toLowerCase()) ||
    p.metodo.toLowerCase().includes(searchTerm.toLowerCase()) ||
    p.fecha.includes(searchTerm)
  );

  return (
    <div className="max-w-6xl mx-auto h-[calc(100vh-8rem)]">
      <header className="mb-6">
        <h2 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
          <DollarSign className="text-teal-600" />
          Finanzas & Pagos
        </h2>
        <p className="text-gray-500 mt-1">Registra ingresos y visualiza el historial de pagos.</p>
      </header>

      {/* Warning if no Drive Folder configured */}
      {isAuthenticated && !financeFolderId && (
        <div className="bg-yellow-50 border border-yellow-200 text-yellow-800 p-4 rounded-xl mb-6 flex items-start gap-3">
          <AlertCircle size={20} className="mt-0.5 shrink-0" />
          <div>
            <p className="font-bold">Carpeta de Drive no configurada</p>
            <p className="text-sm">Ve a configuración y agrega el ID de la carpeta de Google Drive donde quieres guardar las imágenes.</p>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 h-full pb-4">

        {/* LEFT COLUMN: FORM */}
        <div className="lg:col-span-1">
          <form onSubmit={handleSubmit} className="bg-white p-6 rounded-2xl shadow-sm border border-gray-200 space-y-5">
            <h3 className="font-semibold text-gray-800 border-b border-gray-100 pb-2 mb-2">Nuevo Ingreso</h3>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Nombre del Paciente</label>
              <input
                type="text"
                value={patientName}
                onChange={(e) => setPatientName(e.target.value)}
                placeholder="Ej: Laura Nuñez"
                className="w-full p-2.5 border border-gray-200 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none transition-all text-sm"
                required
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Monto</label>
                <div className="relative">
                  <span className="absolute left-3 top-2.5 text-gray-400">$</span>
                  <input
                    type="number"
                    value={amount}
                    onChange={(e) => setAmount(e.target.value)}
                    placeholder="0.00"
                    className="w-full pl-7 p-2.5 border border-gray-200 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none transition-all text-sm"
                    required
                  />
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Método</label>
                <select
                  value={method}
                  onChange={(e) => setMethod(e.target.value)}
                  className="w-full p-2.5 border border-gray-200 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none transition-all bg-white text-sm"
                >
                  <option value="Transferencia">Transferencia</option>
                  <option value="Yape">Yape</option>
                  <option value="Plin">Plin</option>
                  <option value="Efectivo">Efectivo</option>
                  <option value="Tarjeta">Tarjeta</option>
                </select>
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Comprobante</label>
              <div className="border-2 border-dashed border-gray-300 rounded-xl p-4 flex flex-col items-center justify-center text-center hover:bg-gray-50 transition-colors relative cursor-pointer">
                <input
                  type="file"
                  accept="image/*,application/pdf"
                  onChange={handleFileChange}
                  className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                />
                {file ? (
                  <div className="flex items-center gap-2 text-teal-700 font-medium overflow-hidden w-full justify-center">
                    <ImageIcon size={20} className="shrink-0" />
                    <span className="truncate text-sm">{file.name}</span>
                  </div>
                ) : (
                  <>
                    <div className="bg-teal-50 p-2 rounded-full mb-2 text-teal-600">
                      <Upload size={20} />
                    </div>
                    <p className="text-xs text-gray-500">Haz clic para subir imagen</p>
                  </>
                )}
              </div>
            </div>

            <button
              type="submit"
              disabled={status === 'uploading' || !isAuthenticated}
              className={`w-full py-2.5 px-4 rounded-xl font-bold text-white shadow-sm flex items-center justify-center gap-2 transition-all ${
                status === 'uploading' 
                  ? 'bg-gray-400 cursor-wait' 
                  : 'bg-teal-600 hover:bg-teal-700 hover:shadow-md'
              }`}
            >
              {status === 'uploading' ? (
                <>
                  <Loader2 size={18} className="animate-spin" />
                  Subiendo...
                </>
              ) : (
                <>
                  <CheckCircle2 size={18} />
                  Registrar Pago
                </>
              )}
            </button>

