                      <Upload size={20} />
                    </div>
                    <p className="text-xs text-gray-500">Haz clic para subir imagen</p>
                  </>
                )}
              </div>
            </div>

            <button
              type="submit"
              disabled={status === 'uploading' || !isAuthenticated}
              className={`w-full py-2.5 px-4 rounded-xl font-bold text-white shadow-sm flex items-center justify-center gap-2 transition-all ${
                status === 'uploading' 
