import React, { useState } from 'react';
import { uploadFileToDrive, appendPaymentToSheet } from '../services/googleApiService';
import { Payment } from '../types';
import { 
  DollarSign, Upload, CheckCircle2, AlertCircle, Loader2, 
  Image as ImageIcon, ExternalLink, Calendar, Search,
  CreditCard, Smartphone, Banknote, ArrowRightLeft, ChevronDown, CloudOff, Cloud
} from 'lucide-react';

interface FinanceManagerProps {
  isAuthenticated: boolean;
  spreadsheetId: string;
  financeFolderId: string;
  payments: Payment[];
  onAddPayment: (payment: Payment) => void;
}

export const FinanceManager: React.FC<FinanceManagerProps> = ({ 
  isAuthenticated, 
  spreadsheetId, 
  financeFolderId,
  payments,
  onAddPayment 
}) => {
  const [amount, setAmount] = useState('');
  const [patientName, setPatientName] = useState('');
  const [method, setMethod] = useState('Transferencia');
  const [file, setFile] = useState<File | null>(null);
  const [isMethodOpen, setIsMethodOpen] = useState(false);

  const [status, setStatus] = useState<'idle' | 'uploading' | 'success' | 'success_local' | 'error'>('idle');
  const [lastPaymentLink, setLastPaymentLink] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const paymentMethods = [
    { id: 'Transferencia', icon: ArrowRightLeft, color: 'text-blue-600', label: 'Transferencia Bancaria' },
    { id: 'Yape', icon: Smartphone, color: 'text-purple-600', label: 'Yape' },
    { id: 'Plin', icon: Smartphone, color: 'text-cyan-600', label: 'Plin' },
    { id: 'Efectivo', icon: Banknote, color: 'text-green-600', label: 'Efectivo' },
    { id: 'Tarjeta', icon: CreditCard, color: 'text-gray-600', label: 'Tarjeta Crédito/Débito' }
  ];

  const selectedMethodData = paymentMethods.find(m => m.id === method) || paymentMethods[0];

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || !patientName) {
      alert("Por favor completa el nombre y el monto.");
      return;
    }

    setStatus('uploading');

    let finalUrl = '';
    let finalDriveId = '';
    let syncSuccess = false;

    try {
      // 1. Handle File (Cloud vs Local)
      if (file) {
        if (isAuthenticated) {
          try {
            const driveResponse = await uploadFileToDrive(file, financeFolderId);
            finalUrl = driveResponse.webViewLink;
            finalDriveId = driveResponse.id;
          } catch (error) {
            console.error("Fallo subida a Drive, usando local:", error);
            finalUrl = URL.createObjectURL(file); // Fallback local
          }
        } else {
          finalUrl = URL.createObjectURL(file); // Local mode
        }
      }

      const newPayment: Payment = {
        id: crypto.randomUUID(),
        fecha: new Date().toLocaleDateString('es-ES'),
        paciente: patientName,
        monto: parseFloat(amount),
        metodo: method,
        comprobanteUrl: finalUrl,
        driveFileId: finalDriveId
      };

      // 2. Append to Sheets (Cloud)
      if (isAuthenticated && spreadsheetId) {
        try {
          await appendPaymentToSheet(spreadsheetId, newPayment);
          syncSuccess = true;
        } catch (error) {
          console.error("Fallo guardar en Sheet:", error);
          syncSuccess = false;
        }
      }

      // 3. Update Local State (Always happens)
      onAddPayment(newPayment);

      if (isAuthenticated && syncSuccess && finalDriveId) {
        setStatus('success');
        setLastPaymentLink(finalUrl);
      } else {
        setStatus('success_local');
        setLastPaymentLink(null);
      }

      // Reset form
      setAmount('');
      setPatientName('');
      setFile(null);
      setTimeout(() => setStatus('idle'), 5000);

    } catch (error) {
      console.error(error);
      setStatus('error');
    }
  };

  const filteredPayments = payments.filter(p => 
    p.paciente.toLowerCase().includes(searchTerm.toLowerCase()) ||
    p.metodo.toLowerCase().includes(searchTerm.toLowerCase()) ||
    p.fecha.includes(searchTerm)
  );

  return (
    <div className="max-w-6xl mx-auto h-[calc(100vh-8rem)]">
      <header className="mb-6">
        <h2 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
          <DollarSign className="text-teal-600" />
          Finanzas & Pagos
        </h2>
        <div className="flex items-center gap-2 mt-1">
          <p className="text-gray-500">Registra ingresos y visualiza el historial de pagos.</p>
          {isAuthenticated ? (
            <span className="text-xs bg-green-100 text-green-700 px-2 py-0.5 rounded-full flex items-center gap-1">
              <Cloud size={10} /> Sincronizado
            </span>
          ) : (
            <span className="text-xs bg-gray-100 text-gray-500 px-2 py-0.5 rounded-full flex items-center gap-1">
              <CloudOff size={10} /> Local
            </span>
          )}
        </div>
      </header>

      {/* Warning if no Drive Folder configured */}
      {isAuthenticated && !financeFolderId && (
        <div className="bg-yellow-50 border border-yellow-200 text-yellow-800 p-4 rounded-xl mb-6 flex items-start gap-3">
          <AlertCircle size={20} className="mt-0.5 shrink-0" />
          <div>
            <p className="font-bold">Carpeta de Drive no configurada</p>
            <p className="text-sm">Ve a configuración y agrega el ID de la carpeta de Google Drive donde quieres guardar las imágenes.</p>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 h-full pb-4">

        {/* LEFT COLUMN: FORM */}
        <div className="lg:col-span-1">
          <form onSubmit={handleSubmit} className="bg-white p-6 rounded-2xl shadow-sm border border-gray-200 space-y-5">
            <h3 className="font-semibold text-gray-800 border-b border-gray-100 pb-2 mb-2">Nuevo Ingreso</h3>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Nombre del Paciente</label>
              <input
                type="text"
                value={patientName}
                onChange={(e) => setPatientName(e.target.value)}
                placeholder="Ej: Laura Nuñez"
                className="w-full p-2.5 border border-gray-200 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none transition-all text-sm"
                required
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Monto</label>
                <div className="relative">
                  <span className="absolute left-3 top-2.5 text-gray-400">$</span>
                  <input
                    type="number"
                    value={amount}
                    onChange={(e) => setAmount(e.target.value)}
                    placeholder="0.00"
                    className="w-full pl-7 p-2.5 border border-gray-200 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none transition-all text-sm"
                    required
                  />
                </div>
              </div>

              {/* Custom Dropdown for Method */}
              <div className="relative">
                <label className="block text-sm font-medium text-gray-700 mb-1">Método</label>

                <button
                  type="button"
                  onClick={() => setIsMethodOpen(!isMethodOpen)}
                  className="w-full p-2.5 border border-gray-200 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none transition-all bg-white text-sm text-left flex items-center justify-between hover:bg-gray-50 h-[42px]"
                >
                  <div className="flex items-center gap-2 truncate">
                    <selectedMethodData.icon size={16} className={`${selectedMethodData.color}`} />
                    <span className="text-gray-700 truncate">{selectedMethodData.id}</span>
                  </div>
                  <ChevronDown size={16} className={`text-gray-400 shrink-0 transition-transform ${isMethodOpen ? 'rotate-180' : ''}`} />
                </button>

                {/* Backdrop for click outside */}
                {isMethodOpen && (
                  <div className="fixed inset-0 z-10" onClick={() => setIsMethodOpen(false)} />
                )}

                {/* Dropdown Menu */}
                {isMethodOpen && (
                  <div className="absolute z-20 w-full mt-1 bg-white border border-gray-100 rounded-xl shadow-xl max-h-64 overflow-auto p-1 animate-in fade-in zoom-in-95 duration-100 left-0">
                    {paymentMethods.map(m => (
                        <button
                          key={m.id}
                          type="button"
                          onClick={() => { setMethod(m.id); setIsMethodOpen(false); }}
                          className={`w-full flex items-center gap-3 p-2 rounded-lg text-sm transition-colors ${
                            method === m.id ? 'bg-teal-50 text-teal-900' : 'text-gray-600 hover:bg-gray-50'
                          }`}
                        >
                          <div className={`p-1.5 rounded-md ${method === m.id ? 'bg-teal-100 text-teal-700' : 'bg-gray-100 text-gray-500'}`}>
                              <m.icon size={16} />
                          </div>
                          <div className="flex flex-col items-start">
                             <span className="font-medium leading-none">{m.id}</span>
                             <span className="text-[10px] text-gray-400 mt-0.5">{m.label}</span>
                          </div>
                          {method === m.id && <CheckCircle2 size={14} className="ml-auto text-teal-600" />}
                        </button>
                    ))}
                  </div>
                )}
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Comprobante</label>
              <div className="border-2 border-dashed border-gray-300 rounded-xl p-4 flex flex-col items-center justify-center text-center hover:bg-gray-50 transition-colors relative cursor-pointer">
                <input
                  type="file"
                  accept="image/*,application/pdf"
                  onChange={handleFileChange}
                  className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                />
                {file ? (
                  <div className="flex items-center gap-2 text-teal-700 font-medium overflow-hidden w-full justify-center">
                    <ImageIcon size={20} className="shrink-0" />
                    <span className="truncate text-sm">{file.name}</span>
                  </div>
                ) : (
                  <>
                    <div className="bg-teal-50 p-2 rounded-full mb-2 text-teal-600">
                      <Upload size={20} />
                    </div>
                    <p className="text-xs text-gray-500">Haz clic para subir imagen</p>
                  </>
                )}
              </div>
            </div>

            <button
              type="submit"
              disabled={status === 'uploading'}
              className={`w-full py-2.5 px-4 rounded-xl font-bold text-white shadow-sm flex items-center justify-center gap-2 transition-all ${
                status === 'uploading' 
                  ? 'bg-gray-400 cursor-wait' 
                  : 'bg-teal-600 hover:bg-teal-700 hover:shadow-md'
              }`}
            >
              {status === 'uploading' ? (
                <>
                  <Loader2 size={18} className="animate-spin" />
                  Guardando...
                </>
              ) : (
                <>
                  <CheckCircle2 size={18} />
                  Registrar Pago
                </>
              )}
            </button>

            {status === 'success' && (
              <div className="p-3 bg-green-50 text-green-700 rounded-lg text-sm flex flex-col items-start gap-1">
                <div className="flex items-center gap-2 font-medium">
                  <CheckCircle2 size={14} />
                  ¡Guardado y Sincronizado!
                </div>
                {lastPaymentLink && (
                  <a href={lastPaymentLink} target="_blank" rel="noreferrer" className="text-xs underline flex items-center gap-1">
                    Ver en Drive <ExternalLink size={10} />
                  </a>
                )}
              </div>
            )}

            {status === 'success_local' && (
              <div className="p-3 bg-gray-100 text-gray-700 rounded-lg text-sm flex flex-col items-start gap-1">
                <div className="flex items-center gap-2 font-medium">
                  <CheckCircle2 size={14} />
                  Guardado Localmente
                </div>
                <p className="text-xs text-gray-500">El pago se guardó en este dispositivo (no en Google Sheet).</p>
              </div>
            )}

            {status === 'error' && (
              <div className="p-3 bg-red-50 text-red-700 rounded-lg text-xs flex items-center gap-2">
                <AlertCircle size={14} />
                Error al procesar. Intenta nuevamente.
              </div>
            )}
          </form>
        </div>

        {/* RIGHT COLUMN: TABLE */}
        <div className="lg:col-span-2 flex flex-col h-full overflow-hidden">
           <div className="bg-white rounded-2xl shadow-sm border border-gray-200 flex flex-col h-full overflow-hidden">

             {/* Search Header */}
             <div className="px-6 py-4 border-b border-gray-100 bg-gray-50 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                <h3 className="font-semibold text-gray-800">Historial de Pagos</h3>
                <div className="relative">
                  <Search className="absolute left-3 top-2.5 text-gray-400" size={16} />
                  <input 
                    type="text" 
                    placeholder="Buscar pago..." 
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-9 pr-4 py-2 text-sm border border-gray-200 rounded-lg focus:ring-1 focus:ring-teal-500 outline-none w-full sm:w-48"
                  />
                </div>
             </div>

             {/* Table Content */}
             <div className="flex-1 overflow-y-auto">
               <table className="w-full text-left text-sm text-gray-600">
                  <thead className="bg-white sticky top-0 z-10 shadow-sm text-xs uppercase font-semibold text-gray-500">
                    <tr>
                      <th className="px-6 py-3 border-b border-gray-100">Fecha</th>
                      <th className="px-6 py-3 border-b border-gray-100">Paciente</th>
                      <th className="px-6 py-3 border-b border-gray-100">Método</th>
                      <th className="px-6 py-3 border-b border-gray-100 text-right">Monto</th>
                      <th className="px-6 py-3 border-b border-gray-100 text-center">Recibo</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-50">
                    {filteredPayments.length === 0 ? (
                      <tr>
                        <td colSpan={5} className="px-6 py-12 text-center text-gray-400">
                          {searchTerm ? 'No se encontraron pagos.' : 'No hay pagos registrados aún.'}
                        </td>
                      </tr>
                    ) : (
                      filteredPayments.map((payment) => (
                        <tr key={payment.id} className="hover:bg-gray-50 transition-colors">
                          <td className="px-6 py-3 whitespace-nowrap text-xs">
                            <div className="flex items-center gap-2">
                              <Calendar size={12} className="text-gray-400" />
                              {payment.fecha}
                            </div>
                          </td>
                          <td className="px-6 py-3 font-medium text-gray-800">{payment.paciente}</td>
                          <td className="px-6 py-3">
                             <span className={`px-2 py-0.5 rounded text-xs ${
                                payment.metodo === 'Transferencia' ? 'bg-blue-50 text-blue-700' :
                                payment.metodo === 'Efectivo' ? 'bg-green-50 text-green-700' :
                                'bg-gray-100 text-gray-600'
                             }`}>
                               {payment.metodo}
                             </span>
                          </td>
                          <td className="px-6 py-3 text-right font-mono font-medium text-gray-900">
                            ${payment.monto.toFixed(2)}
                          </td>
                          <td className="px-6 py-3 text-center">
                            {payment.comprobanteUrl ? (
                              <a 
                                href={payment.comprobanteUrl} 
                                target="_blank" 
                                rel="noreferrer" 
                                className="inline-flex items-center justify-center p-1.5 text-teal-600 hover:bg-teal-50 rounded transition-colors"
                                title="Ver comprobante"
                              >
                                <ExternalLink size={16} />
                              </a>
                            ) : (
                              <span className="text-gray-300">-</span>
                            )}
                          </td>
                        </tr>
                      ))
                    )}
                  </tbody>
               </table>
             </div>

             {/* Footer Summary */}
             <div className="p-4 bg-gray-50 border-t border-gray-200 text-right">
                <span className="text-sm text-gray-500 mr-2">Total en vista:</span>
                <span className="text-lg font-bold text-gray-800">
                  ${filteredPayments.reduce((acc, curr) => acc + curr.monto, 0).toFixed(2)}
                </span>
             </div>

           </div>
        </div>

      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { PatientManager } from './components/PatientManager';
import { DigitalNotebook } from './components/DigitalNotebook';
import { FinanceManager } from './components/FinanceManager';
import { WaitingListManager } from './components/WaitingListManager'; // Import new component
import { Dashboard } from './components/Dashboard';
import { Patient, Task, CalendarEvent, ViewState, AppSettings, WaitingListEntry, Payment } from './types';
import { initGoogleServices, handleLogin, handleLogout } from './services/googleApiService';
import { Settings as SettingsIcon, AlertCircle, Menu, HeartPulse, LogIn, Save, LogOut, Database } from 'lucide-react';

// Data Retention Configuration
const RETENTION_DAYS = 90;
const MS_PER_DAY = 24 * 60 * 60 * 1000;
const RETENTION_MS = RETENTION_DAYS * MS_PER_DAY;

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // App State
  const [patients, setPatients] = useState<Patient[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [waitingList, setWaitingList] = useState<WaitingListEntry[]>([]);
  const [payments, setPayments] = useState<Payment[]>([]); // New State for Payments
  const [dataLoaded, setDataLoaded] = useState(false);

  // Auth & Settings State
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [settings, setSettings] = useState<AppSettings>({
    googleClientId: localStorage.getItem('googleClientId') || '',
    spreadsheetId: localStorage.getItem('spreadsheetId') || '',
    financeFolderId: localStorage.getItem('financeFolderId') || ''
  });
  const [isGapiReady, setIsGapiReady] = useState(false);

  // --- Persistence Logic ---

  // 1. Load data on mount
  useEffect(() => {
    const loadData = (key: string, setter: React.Dispatch<React.SetStateAction<any[]>>) => {
      const stored = localStorage.getItem(`app_data_${key}`);
      if (stored) {
        try {
          const parsed = JSON.parse(stored);
          const age = Date.now() - parsed.timestamp;

          if (age < RETENTION_MS) {
            setter(parsed.data);
          } else {
            console.log(`Data for ${key} expired. Clearing.`);
            localStorage.removeItem(`app_data_${key}`);
          }
        } catch (e) {
          console.error(`Error loading ${key}`, e);
        }
      }
    };

    loadData('patients', setPatients);
    loadData('tasks', setTasks);
    loadData('events', setEvents);
    loadData('waitingList', setWaitingList);
    loadData('payments', setPayments); // Load payments
    setDataLoaded(true);
  }, []);

  // 2. Save data on change
  useEffect(() => {
    if (!dataLoaded) return;
    localStorage.setItem('app_data_patients', JSON.stringify({ timestamp: Date.now(), data: patients }));
  }, [patients, dataLoaded]);

  useEffect(() => {
    if (!dataLoaded) return;
    localStorage.setItem('app_data_tasks', JSON.stringify({ timestamp: Date.now(), data: tasks }));
  }, [tasks, dataLoaded]);

  useEffect(() => {
    if (!dataLoaded) return;
    localStorage.setItem('app_data_events', JSON.stringify({ timestamp: Date.now(), data: events }));
  }, [events, dataLoaded]);

  useEffect(() => {
    if (!dataLoaded) return;
    localStorage.setItem('app_data_waitingList', JSON.stringify({ timestamp: Date.now(), data: waitingList }));
  }, [waitingList, dataLoaded]);

  useEffect(() => {
    if (!dataLoaded) return;
    localStorage.setItem('app_data_payments', JSON.stringify({ timestamp: Date.now(), data: payments }));
  }, [payments, dataLoaded]);

  // --- End Persistence Logic ---

  useEffect(() => {
    if (settings.googleClientId) {
      initGoogleServices(settings.googleClientId, (success) => {
        setIsGapiReady(success);
      });
    }
  }, [settings.googleClientId]);

  const onLogin = async () => {
    try {
      await handleLogin();
      setIsAuthenticated(true);
    } catch (error) {
      alert("Fallo al iniciar sesión en Google");
    }
  };

  const onLogout = () => {
    handleLogout();
    setIsAuthenticated(false);
  };

  const saveSettings = () => {
    localStorage.setItem('googleClientId', settings.googleClientId);
    localStorage.setItem('spreadsheetId', settings.spreadsheetId);
    localStorage.setItem('financeFolderId', settings.financeFolderId);
    window.location.reload(); 
  };

  // State handlers
  const handleAddPatient = (patient: Patient) => {
    setPatients(prev => [patient, ...prev]);
  };

  const handleDeletePatient = (id: string) => {
    setPatients(prev => prev.filter(p => p.id !== id));
  };

  const handleAddTasks = (newTasks: Task[]) => {
    setTasks(prev => [...prev, ...newTasks]);
  };

  const handleAddEvents = (newEvents: CalendarEvent[]) => {
    setEvents(prev => [...prev, ...newEvents]);
  };

  const handleToggleTask = (id: string) => {
    setTasks(prev => prev.map(t => t.id === id ? { ...t, isDone: !t.isDone } : t));
  };

  const handleDeleteTask = (id: string) => {
    setTasks(prev => prev.filter(t => t.id !== id));
  };

  const handleDeleteEvent = (id: string) => {
    setEvents(prev => prev.filter(e => e.id !== id));
  };

  const handleAddWaitingEntry = (entry: WaitingListEntry) => {
    setWaitingList(prev => [...prev, entry]);
  };

  const handleRemoveWaitingEntry = (id: string) => {
    setWaitingList(prev => prev.filter(entry => entry.id !== id));
  };

  const handleAddPayment = (payment: Payment) => {
    setPayments(prev => [payment, ...prev]);
  };

  const handleDeletePayment = (id: string) => {
    setPayments(prev => prev.filter(p => p.id !== id));
  };

  return (
    <div className="flex h-screen bg-[#F8FAFC] overflow-hidden">
      {/* Mobile Header */}
      <div className="md:hidden fixed top-0 left-0 right-0 h-16 bg-white border-b border-gray-200 z-30 flex items-center justify-between px-4">
        <div className="flex items-center gap-2 text-teal-600">
          <HeartPulse size={24} />
          <span className="font-bold text-lg text-gray-800">Idguie</span>
        </div>
        <button 
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
          className="p-2 text-gray-600 hover:bg-gray-100 rounded-lg"
        >
          <Menu size={24} />
        </button>
      </div>

      {/* Sidebar Overlay for Mobile */}
      {isMobileMenuOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 md:hidden"
          onClick={() => setIsMobileMenuOpen(false)}
        />
      )}

      {/* Sidebar - Responsive */}
      <div className={`
        fixed inset-y-0 left-0 z-50 transform transition-transform duration-300 ease-in-out md:relative md:translate-x-0
        ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <Sidebar 
          currentView={currentView} 
          onChangeView={setCurrentView} 
          onCloseMobile={() => setIsMobileMenuOpen(false)}
        />
      </div>

      {/* Main Content */}
      <main className="flex-1 overflow-auto p-4 md:p-8 pt-20 md:pt-8 w-full relative">
        {/* Top Bar: Auth Status */}
        <div className="flex justify-end mb-4 gap-3">
           <div className="hidden md:flex items-center gap-2 text-xs text-gray-400 bg-gray-50 px-3 py-1 rounded-full border border-gray-100">
              <Database size={12} />
              <span>Memoria local: {RETENTION_DAYS} días</span>
           </div>

          {!isAuthenticated ? (
            <button 
              onClick={onLogin} 
              disabled={!isGapiReady}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg font-medium text-sm transition-all ${
                isGapiReady 
                  ? 'bg-blue-600 text-white hover:bg-blue-700 shadow-sm' 
                  : 'bg-gray-200 text-gray-400 cursor-not-allowed'
              }`}
            >
              <LogIn size={16} />
              {isGapiReady ? 'Conectar con Google' : 'Configura Client ID'}
            </button>
          ) : (
            <button 
              onClick={onLogout}
              className="flex items-center gap-2 px-4 py-2 bg-white border border-gray-200 text-gray-600 hover:bg-gray-50 rounded-lg font-medium text-sm transition-all"
            >
              <LogOut size={16} />
              Desconectar
            </button>
          )}
        </div>

        {/* API Key Warning Overlay */}
        {!process.env.API_KEY && (
           <div className="mb-6 bg-red-50 border border-red-200 rounded-lg p-4 flex items-start gap-3">
             <AlertCircle className="text-red-500 mt-0.5 shrink-0" />
             <div>
               <h4 className="font-bold text-red-700">Falta la API Key de Gemini</h4>
               <p className="text-sm text-red-600 break-words">
                 Esta aplicación requiere una Google Gemini API Key en el entorno.
               </p>
             </div>
           </div>
        )}

        {currentView === ViewState.DASHBOARD && (
          <Dashboard 
            patients={patients}
            tasks={tasks}
            events={events}
            onChangeView={setCurrentView}
          />
        )}

        {currentView === ViewState.PATIENTS && (
          <PatientManager 
            patients={patients}
            onAddPatient={handleAddPatient}
            onDeletePatient={handleDeletePatient}
            isAuthenticated={isAuthenticated}
            spreadsheetId={settings.spreadsheetId}
          />
        )}

        {currentView === ViewState.NOTEBOOK && (
          <DigitalNotebook 
            tasks={tasks}
            events={events}
            onAddTasks={handleAddTasks}
            onAddEvents={handleAddEvents}
            onToggleTask={handleToggleTask}
            onDeleteTask={handleDeleteTask}
            onDeleteEvent={handleDeleteEvent}
            isAuthenticated={isAuthenticated}
          />
        )}

        {currentView === ViewState.FINANCE && (
          <FinanceManager 
            isAuthenticated={isAuthenticated}
            spreadsheetId={settings.spreadsheetId}
            financeFolderId={settings.financeFolderId}
            payments={payments}
            onAddPayment={handleAddPayment}
            onDeletePayment={handleDeletePayment}
          />
        )}

        {currentView === ViewState.WAITING_LIST && (
          <WaitingListManager 
            waitingList={waitingList}
            onAddEntry={handleAddWaitingEntry}
            onRemoveEntry={handleRemoveWaitingEntry}
          />
        )}

        {currentView === ViewState.SETTINGS && (
          <div className="max-w-2xl mx-auto bg-white p-6 md:p-8 rounded-2xl shadow-sm border border-gray-100">
            <div className="flex items-center gap-3 mb-6 pb-6 border-b border-gray-100">
              <div className="w-12 h-12 bg-gray-100 rounded-full flex items-center justify-center text-gray-500 shrink-0">
                <SettingsIcon size={24} />
              </div>
              <div>
                <h2 className="text-xl font-bold text-gray-800">Configuración</h2>
                <p className="text-gray-500 text-sm">Conexiones con Google Workspace</p>
              </div>
            </div>

            <div className="space-y-6">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Google Client ID (OAuth 2.0)</label>
                <input 
                  type="text" 
                  value={settings.googleClientId}
                  onChange={(e) => setSettings({...settings, googleClientId: e.target.value})}
                  className="w-full p-2 border border-gray-300 rounded-lg text-sm font-mono focus:ring-2 focus:ring-teal-500 outline-none"
                  placeholder="xxxx-xxxx.apps.googleusercontent.com"
                />
                <p className="text-xs text-gray-400 mt-1">Necesario para Sheets, Tasks, Calendar y Drive.</p>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Google Sheet ID</label>
                <input 
                  type="text" 
                  value={settings.spreadsheetId}
                  onChange={(e) => setSettings({...settings, spreadsheetId: e.target.value})}
                  className="w-full p-2 border border-gray-300 rounded-lg text-sm font-mono focus:ring-2 focus:ring-teal-500 outline-none"
                  placeholder="1BxiMVs0XRA5nFMdKb..."
                />
                <p className="text-xs text-gray-400 mt-1">El ID del Sheet. Debe contener una pestaña llamada 'Sheet1' (pacientes) y 'Pagos' (finanzas).</p>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Google Drive Folder ID (Para Comprobantes)</label>
                <input 
                  type="text" 
                  value={settings.financeFolderId}
                  onChange={(e) => setSettings({...settings, financeFolderId: e.target.value})}
                  className="w-full p-2 border border-gray-300 rounded-lg text-sm font-mono focus:ring-2 focus:ring-teal-500 outline-none"
                  placeholder="1z-XXXXXXXXXXXXXXXXXXXX"
                />
                <p className="text-xs text-gray-400 mt-1">El ID de la carpeta en Drive donde se guardarán las imágenes (lo encuentras en la URL de la carpeta).</p>
              </div>

              <div className="pt-4">
                <button 
                  onClick={saveSettings}
