        <h2 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
          <DollarSign className="text-teal-600" />
          Finanzas & Pagos
        </h2>
        <div className="flex items-center gap-2 mt-1">
          <p className="text-gray-500">Registra ingresos y visualiza el historial de pagos.</p>
          {isAuthenticated ? (
            <span className="text-xs bg-green-100 text-green-700 px-2 py-0.5 rounded-full flex items-center gap-1">
              <Cloud size={10} /> Sincronizado
            </span>
          ) : (
            <span className="text-xs bg-gray-100 text-gray-500 px-2 py-0.5 rounded-full flex items-center gap-1">
              <CloudOff size={10} /> Local
