import React, { useState, useEffect } from 'react';
import { parsePatientData } from '../services/geminiService';
import { appendPatientToSheet } from '../services/googleApiService';
import { Patient } from '../types';
import { Sparkles, FileSpreadsheet, Trash2, Loader2, Search, ChevronLeft, ChevronRight, UserPlus, UserCheck, CloudUpload, X } from 'lucide-react';

interface PatientManagerProps {
  patients: Patient[];
  onAddPatient: (patient: Patient) => void;
  onDeletePatient: (id: string) => void;
  isAuthenticated: boolean;
  spreadsheetId: string;
}

export const PatientManager: React.FC<PatientManagerProps> = ({ patients, onAddPatient, onDeletePatient, isAuthenticated, spreadsheetId }) => {
  const [inputText, setInputText] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [statusMessage, setStatusMessage] = useState<{type: 'error' | 'success', text: string} | null>(null);

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10;

  useEffect(() => {
    setCurrentPage(1);
  }, [searchTerm, patients.length]);

  const handleProcess = async () => {
    if (!inputText.trim()) return;

    setIsProcessing(true);
    setStatusMessage(null);
    try {
      // 1. Parse with Gemini
      const parsedData = await parsePatientData(inputText);

      if (parsedData) {
        const newPatient: Patient = {
          id: crypto.randomUUID(),
          fecha: new Date().toLocaleDateString('es-ES'),
          ...parsedData
        };

        // 2. Send to Google Sheets if configured
        if (isAuthenticated && spreadsheetId) {
          try {
             await appendPatientToSheet(spreadsheetId, newPatient);
             // 3. Update local UI only if Sheet update was successful (or to reflect optimistic UI)
             onAddPatient(newPatient);
             setInputText('');
             setStatusMessage({ type: 'success', text: 'Paciente registrado en Google Sheets y localmente.' });
          } catch (sheetError) {
             console.error(sheetError);
             setStatusMessage({ type: 'error', text: 'Datos analizados, pero falló al guardar en Google Sheet. Revisa permisos/ID.' });
             // Still add locally so data isn't lost? Let's strictly require Sheet success for "Real Integration" feel, 
             // or add locally and warn. Let's add locally to be safe.
             onAddPatient(newPatient);
          }
        } else {
           // Offline/No-Auth mode
           onAddPatient(newPatient);
           setInputText('');
           setStatusMessage({ type: 'success', text: 'Paciente registrado localmente (Google Sheets no conectado).' });
        }

      } else {
        setStatusMessage({ type: 'error', text: 'No se pudo interpretar la información. Intenta ser más claro.' });
      }
    } catch (err: any) {
      setStatusMessage({ type: 'error', text: err.message || 'Error al procesar.' });
    } finally {
      setIsProcessing(false);
    }
  };

  const exportToCSV = () => {
    const headers = ["Fecha", "Nombre", "Apellido", "Edad", "Documento", "Descripción", "Psicólogo", "Tipo"];
    const rows = patients.map(p => [
      p.fecha,
      p.nombre,
      p.apellido,
      p.edad,
      p.documentoIdentidad,
      `"${p.descripcion}"`,
      p.psicologo,
      p.tipo
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
      + [headers.join(','), ...rows.map(e => e.join(','))].join('\n');

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "matriz_pacientes.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleDelete = (id: string) => {
    if (window.confirm("¿Estás segura de que quieres eliminar a este paciente de la vista local?")) {
      onDeletePatient(id);
    }
  };

  const filteredPatients = patients.filter(patient => {
    const term = searchTerm.toLowerCase();
    const fullName = `${patient.nombre} ${patient.apellido}`.toLowerCase();
    return (
      fullName.includes(term) ||
      patient.fecha.includes(term) ||
      patient.psicologo.toLowerCase().includes(term) ||
      patient.documentoIdentidad.includes(term) ||
      patient.tipo.toLowerCase().includes(term)
    );
  });

  const totalPages = Math.ceil(filteredPatients.length / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const displayedPatients = filteredPatients.slice(startIndex, startIndex + itemsPerPage);

  const goToPreviousPage = () => setCurrentPage(prev => Math.max(prev - 1, 1));
  const goToNextPage = () => setCurrentPage(prev => Math.min(prev + 1, totalPages));

  return (
    <div className="space-y-6 max-w-6xl mx-auto">
      <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-8 gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Matriz de Pacientes</h2>
          <div className="flex items-center gap-2 mt-1">
             <p className="text-gray-500">Registra pacientes en tu Google Sheet.</p>
             {isAuthenticated && spreadsheetId ? (
               <span className="text-xs bg-green-100 text-green-700 px-2 py-0.5 rounded-full flex items-center gap-1">
                 <CloudUpload size={10} /> Conectado a Sheets
               </span>
             ) : (
               <span className="text-xs bg-gray-100 text-gray-500 px-2 py-0.5 rounded-full">Modo Local</span>
             )}
          </div>
        </div>
        <button 
          onClick={exportToCSV}
          className="w-full sm:w-auto flex items-center justify-center gap-2 bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded-lg font-medium transition-colors shadow-sm"
        >
          <FileSpreadsheet size={18} />
          Exportar CSV
        </button>
      </header>

      {/* Input Section */}
      <div className="bg-white p-4 md:p-6 rounded-2xl shadow-sm border border-gray-200">
        <label className="block text-sm font-semibold text-gray-700 mb-2">
          Entrada Rápida
        </label>
        <div className="relative">
          <textarea
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            placeholder="Ej: Laura nunez, 32, 40200564348, separacion, Dra Aurora (primera vez)"
            className="w-full h-32 p-4 bg-gray-800 border border-gray-700 rounded-xl focus:ring-2 focus:ring-teal-500 focus:border-teal-500 transition-all resize-none text-white placeholder-gray-400 pb-16"
          />
          <button
            onClick={handleProcess}
            disabled={isProcessing || !inputText}
            className={`absolute bottom-4 right-4 flex items-center gap-2 px-4 py-2 rounded-lg font-medium text-white transition-all ${
              isProcessing || !inputText 
                ? 'bg-gray-600 cursor-not-allowed' 
                : 'bg-teal-600 hover:bg-teal-700 shadow-md hover:shadow-lg'
            }`}
          >
            {isProcessing ? (
              <>
                <Loader2 size={18} className="animate-spin" />
                <span className="hidden sm:inline">Procesando...</span>
              </>
            ) : (
              <>
                <Sparkles size={18} />
                <span className="hidden sm:inline">Procesar y Guardar</span>
                <span className="sm:hidden">Procesar</span>
              </>
            )}
          </button>
        </div>
        {statusMessage && (
          <p className={`text-sm mt-2 ${statusMessage.type === 'error' ? 'text-red-500' : 'text-green-600'}`}>
            {statusMessage.text}
          </p>
        )}
      </div>

      {/* Filter & Table Section */}
      <div className="space-y-4">
        {/* Search Bar */}
        <div className="relative">
          <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
            <Search className="h-5 w-5 text-gray-400" />
          </div>
          <input
            type="text"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="block w-full pl-10 pr-10 py-2 border border-gray-200 rounded-xl leading-5 bg-white placeholder-gray-400 focus:outline-none focus:ring-1 focus:ring-teal-500 focus:border-teal-500 sm:text-sm shadow-sm"
            placeholder="Buscar por nombre, fecha o psicólogo..."
          />
          {searchTerm && (
            <button 
              onClick={() => setSearchTerm('')}
              className="absolute inset-y-0 right-0 pr-3 flex items-center text-gray-400 hover:text-gray-600 transition-colors"
            >
              <X size={16} />
            </button>
          )}
        </div>

        {/* Table */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left text-sm text-gray-600">
              <thead className="bg-gray-50 border-b border-gray-200 text-xs uppercase font-semibold text-gray-500 tracking-wider">
                <tr>
                  <th className="px-6 py-4">Fecha</th>
                  <th className="px-6 py-4">Nombre Completo</th>
                  <th className="px-6 py-4">Edad</th>
                  <th className="px-6 py-4">Documento</th>
                  <th className="px-6 py-4">Motivo</th>
                  <th className="px-6 py-4">Psicólogo</th>
                  <th className="px-6 py-4">Tipo</th>
                  <th className="px-6 py-4 text-right">Acciones</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {filteredPatients.length === 0 ? (
                  <tr>
                    <td colSpan={8} className="px-6 py-12 text-center text-gray-400">
                      {searchTerm ? <span>No se encontraron resultados para "{searchTerm}".</span> : <span>No hay pacientes registrados.</span>}
                    </td>
                  </tr>
                ) : (
                  displayedPatients.map((patient) => (
                    <tr key={patient.id} className="hover:bg-teal-50/40 transition-colors duration-200">
                      <td className="px-6 py-4 whitespace-nowrap">{patient.fecha}</td>
                      <td className="px-6 py-4 font-bold text-base text-gray-900 whitespace-nowrap">
                        {patient.nombre} {patient.apellido}
                      </td>
                      <td className="px-6 py-4">{patient.edad}</td>
                      <td className="px-6 py-4 font-mono text-xs text-gray-500">{patient.documentoIdentidad}</td>
                      <td className="px-6 py-4 max-w-xs truncate text-gray-500" title={patient.descripcion}>
                        {patient.descripcion}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-100 text-blue-800">
                          {patient.psicologo}
                        </span>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <span className={`inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full text-xs font-medium ${
                          patient.tipo === 'Nuevo' ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-600'
                        }`}>
                          {patient.tipo === 'Nuevo' ? <UserPlus size={12} /> : <UserCheck size={12} />}
                          {patient.tipo}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <button 
                          onClick={() => handleDelete(patient.id)}
                          className="text-gray-400 hover:text-red-500 transition-colors"
                        >
                          <Trash2 size={16} />
                        </button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>

          {/* Pagination Controls */}
          {filteredPatients.length > 0 && (
            <div className="bg-gray-50 px-6 py-4 border-t border-gray-200 flex items-center justify-between">
              <div className="text-sm text-gray-500">
                Mostrando <span className="font-medium">{startIndex + 1}</span> a <span className="font-medium">{Math.min(startIndex + itemsPerPage, filteredPatients.length)}</span> de <span className="font-medium">{filteredPatients.length}</span>
              </div>
              <div className="flex items-center gap-2">
                <button
                  onClick={goToPreviousPage}
                  disabled={currentPage === 1}
                  className={`p-2 rounded-lg border border-gray-300 transition-all ${currentPage === 1 ? 'bg-gray-100 text-gray-400' : 'bg-white hover:bg-gray-50'}`}
                >
                  <ChevronLeft size={16} />
                </button>
                <div className="flex items-center gap-1 px-2">
                  <span className="text-sm font-medium text-gray-700">{currentPage}</span>
                  <span className="text-sm text-gray-400">/ {totalPages || 1}</span>
                </div>
                <button
                  onClick={goToNextPage}
                  disabled={currentPage === totalPages || totalPages === 0}
                  className={`p-2 rounded-lg border border-gray-300 transition-all ${currentPage === totalPages ? 'bg-gray-100 text-gray-400' : 'bg-white hover:bg-gray-50'}`}
                >
                  <ChevronRight size={16} />
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { WaitingListEntry } from '../types';
import { Hourglass, UserPlus, Phone, Trash2, MessageCircle, Clock, CalendarClock } from 'lucide-react';

interface WaitingListManagerProps {
  waitingList: WaitingListEntry[];
  onAddEntry: (entry: WaitingListEntry) => void;
  onRemoveEntry: (id: string) => void;
}

export const WaitingListManager: React.FC<WaitingListManagerProps> = ({ waitingList, onAddEntry, onRemoveEntry }) => {
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [preference, setPreference] = useState('');
  const [notes, setNotes] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !phone) return;

    const newEntry: WaitingListEntry = {
      id: crypto.randomUUID(),
      nombre: name,
      telefono: phone,
      preferenciaHoraria: preference,
      notas: notes,
      fechaAgregado: Date.now()
    };

    onAddEntry(newEntry);
    setName('');
    setPhone('');
    setPreference('');
    setNotes('');
  };

  const handleWhatsAppClick = (entry: WaitingListEntry) => {
    // Basic phone cleaning
    const cleanPhone = entry.telefono.replace(/\D/g, ''); 

    // Construct message
    const message = `Hola ${entry.nombre}, te escribo del Centro de Bienestar. Se liberó un espacio en la agenda [AGREGAR HORA AQUÍ], ¿te interesa tomarlo?`;

    // Open WhatsApp
    const url = `https://wa.me/${cleanPhone}?text=${encodeURIComponent(message)}`;
    window.open(url, '_blank');
  };

  const handleDelete = (id: string) => {
    if (window.confirm("¿Estás segura de que quieres eliminar a este paciente de la lista de espera?")) {
      onRemoveEntry(id);
    }
  };

  const formatWaitTime = (timestamp: number) => {
    const days = Math.floor((Date.now() - timestamp) / (1000 * 60 * 60 * 24));
    if (days === 0) return 'Hoy';
    if (days === 1) return 'Hace 1 día';
    return `Hace ${days} días`;
  };

  return (
    <div className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-8 h-[calc(100vh-8rem)]">

      {/* Left Column: Form */}
      <div className="lg:col-span-1 space-y-6">
        <div>
          <h2 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
            <Hourglass className="text-teal-600" />
            Lista de Espera
          </h2>
          <p className="text-gray-500 mt-1 text-sm">
            Registra pacientes interesados para cubrir cancelaciones de último minuto.
          </p>
        </div>

        <form onSubmit={handleSubmit} className="bg-white p-6 rounded-2xl shadow-sm border border-gray-200 space-y-4">
           <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Nombre del Paciente</label>
            <div className="relative">
              <UserPlus className="absolute left-3 top-3 text-gray-400" size={18} />
              <input
                type="text"
                value={name}
                onChange={(e) => setName(e.target.value)}
                placeholder="Ej: Juan Pérez"
                className="w-full pl-10 p-2.5 border border-gray-200 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none text-sm"
                required
              />
            </div>
           </div>

           <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Teléfono (WhatsApp)</label>
            <div className="relative">
              <Phone className="absolute left-3 top-3 text-gray-400" size={18} />
              <input
                type="tel"
                value={phone}
                onChange={(e) => setPhone(e.target.value)}
                placeholder="Ej: 51999999999"
                className="w-full pl-10 p-2.5 border border-gray-200 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none text-sm"
                required
              />
            </div>
            <p className="text-xs text-gray-400 mt-1">Incluye código de país si es necesario (ej: 51 para Perú).</p>
           </div>

           <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Preferencia Horaria</label>
            <div className="relative">
              <CalendarClock className="absolute left-3 top-3 text-gray-400" size={18} />
              <input
                type="text"
                value={preference}
                onChange={(e) => setPreference(e.target.value)}
                placeholder="Ej: Solo mañanas, Martes tardes..."
                className="w-full pl-10 p-2.5 border border-gray-200 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none text-sm"
              />
            </div>
           </div>

           <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Notas Adicionales</label>
            <textarea
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              placeholder="Ej: Paciente urgente..."
              className="w-full p-3 border border-gray-200 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none text-sm resize-none h-20"
            />
           </div>

           <button
            type="submit"
            className="w-full bg-teal-600 hover:bg-teal-700 text-white font-medium py-2.5 rounded-lg transition-colors flex items-center justify-center gap-2"
           >
             <UserPlus size={18} />
             Agregar a Lista
           </button>
        </form>

        <div className="bg-blue-50 border border-blue-100 p-4 rounded-xl text-sm text-blue-800">
          <p className="font-bold mb-1">💡 Estrategia de Ingresos</p>
          <p>Cuando se libere un espacio, busca aquí a alguien con horario compatible y envíale un WhatsApp al instante.</p>
        </div>
      </div>

      {/* Right Column: List */}
      <div className="lg:col-span-2 flex flex-col h-full overflow-hidden">
        <div className="bg-white rounded-2xl shadow-sm border border-gray-200 flex-1 flex flex-col overflow-hidden">
          <div className="px-6 py-4 border-b border-gray-100 bg-gray-50 flex items-center justify-between">
            <h3 className="font-semibold text-gray-800">Pacientes en Espera ({waitingList.length})</h3>
            <span className="text-xs text-gray-500">Ordenado por antigüedad</span>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-3">
            {waitingList.length === 0 && (
              <div className="h-full flex flex-col items-center justify-center text-gray-400">
                <Hourglass size={48} className="mb-4 opacity-20" />
                <p>La lista de espera está vacía.</p>
              </div>
            )}

            {waitingList.map((entry) => (
              <div key={entry.id} className="group bg-white border border-gray-100 rounded-xl p-4 hover:shadow-md transition-all flex flex-col sm:flex-row sm:items-center gap-4">

                {/* Info */}
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 mb-1">
                    <h4 className="font-bold text-gray-900 truncate">{entry.nombre}</h4>
                    <span className="text-xs bg-gray-100 text-gray-500 px-2 py-0.5 rounded-full flex items-center gap-1">
                      <Clock size={10} /> {formatWaitTime(entry.fechaAgregado)}
                    </span>
                  </div>
                  <div className="text-sm text-gray-600 mb-1 flex items-center gap-2">
                     <span className="font-medium text-teal-700 bg-teal-50 px-2 py-0.5 rounded text-xs">
                        Pref: {entry.preferenciaHoraria || 'Sin preferencia'}
                     </span>
                     <span className="text-gray-400">|</span>
                     <span>{entry.telefono}</span>
                  </div>
                  {entry.notas && (
                    <p className="text-xs text-gray-500 italic truncate">{entry.notas}</p>
                  )}
                </div>

                {/* Actions */}
                <div className="flex items-center gap-2 sm:border-l sm:border-gray-100 sm:pl-4">
                  <button
                    onClick={() => handleWhatsAppClick(entry)}
                    className="flex items-center gap-2 bg-green-500 hover:bg-green-600 text-white px-4 py-2 rounded-lg font-medium text-sm transition-colors shadow-sm"
                    title="Enviar WhatsApp de espacio libre"
                  >
                    <MessageCircle size={18} />
                    <span className="hidden sm:inline">Ofrecer Espacio</span>
                    <span className="sm:hidden">WhatsApp</span>
                  </button>

                  <button
                    onClick={() => handleDelete(entry.id)}
                    className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                    title="Eliminar de la lista"
                  >
                    <Trash2 size={18} />
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

    </div>
  );
};

