                  <tbody className="divide-y divide-gray-50 dark:divide-gray-700">
                    {filteredPayments.length === 0 ? (
                      <tr>
                        <td colSpan={6} className="px-6 py-12 text-center text-gray-400 dark:text-gray-500">
