                      <div>
                        <p className="font-bold text-sm">Google Workspace (Datos)</p>
                        <p className="text-xs opacity-80">{isAuthenticated ? `Conectado como ${userProfile?.name || 'Usuario'}` : 'Desconectado'}</p>
